var json_Excel1xlsx22222_1 = {"type":"FeatureCollection","name":"Excel1xlsx22222_1","crs":{"type":"name","properties":{"name":"urn:ogc:def:crs:OGC:1.3:CRS84"}},"features":[{"type":"Feature","properties":{"序号":1.0,"姓名":"欧阳炯","朝代":"五代十国后蜀","籍贯(原名)":"益州华阳","籍贯(现代)":"成都双流区","经度":103.93,"纬度":30.58,"简介":"益州华阳（今属四川成都市）人，五代十国时后蜀词人。在后蜀任职为中书舍人。据《宣和画谱》载，他事孟昶时历任翰林学士、门下侍郎同平章事，随孟昶降宋后，授为散骑常侍，工诗文，特别长于词，又善长笛，是花间派重要作家。","主要作品":"今存文两篇，诗五首，词四十七首。"},"geometry":{"type":"Point","coordinates":[103.93,30.58]}},{"type":"Feature","properties":{"序号":2.0,"姓名":"范镇","朝代":"北宋","籍贯(原名)":"华阳县","籍贯(现代)":"成都双流区","经度":103.93,"纬度":30.58,"简介":"字景仁，苏轼在《范景仁墓志铭》一文说：“其文清丽简远，学者以为师法。”、“临大节，决大议，色和而语壮，常欲继之以死，虽在万乘前，无所屈……”。","主要作品":"1. 《文集》一百卷2. 《谏垣集》十卷3. 《内制集》三十卷4. 《外制集》十卷5. 《正言》三卷6. 《乐书》三卷7. 《国朝韵对》三卷8. 《国朝事始》一卷9. 《东斋记事》十卷10. 《刀笔》八卷"},"geometry":{"type":"Point","coordinates":[103.93,30.58]}},{"type":"Feature","properties":{"序号":3.0,"姓名":"范祖禹","朝代":"北宋","籍贯(原名)":"华阳县","籍贯(现代)":"成都双流区","经度":103.93,"纬度":30.58,"简介":"字淳甫（淳，或作醇、纯，甫或作父），一字梦得。北宋著名史学家、文学家、诗人，“三范修史”之一。","主要作品":"诗文集《范太史集》，共五十五卷。"},"geometry":{"type":"Point","coordinates":[103.93,30.58]}},{"type":"Feature","properties":{"序号":4.0,"姓名":"彭乘","朝代":"北宋","籍贯(原名)":"华阳县","籍贯(现代)":"成都双流区","经度":103.93,"纬度":30.58,"简介":"字利建。天禧初，以寇准荐，授馆阁校勘，改天平军节度推官。预校《南北史》、《隋书》。迁集贤校理。知普州，兴学教士。历州军长官及监司。召修起居注，擢知制诰，为翰林学士，领吏部流内铨、三班院，充群牧使。性质重寡言，聚书万余卷，皆手自刊校。晚年典赞命，而文辞欠工。","主要作品":"代表作《赠喻化成》。"},"geometry":{"type":"Point","coordinates":[103.93,30.58]}},{"type":"Feature","properties":{"序号":5.0,"姓名":"王琪","朝代":"北宋","籍贯(原名)":"华阳县","籍贯(现代)":"成都双流区","经度":103.93,"纬度":30.58,"简介":"王罕之子，王珪从兄。进士及第，曾任江都主簿。是著名的豪放派词人，《宋史》附传王珪。","主要作品":"今有周泳先辑《谪仙长短句》一辑。《全宋词》录其词十一首。"},"geometry":{"type":"Point","coordinates":[103.93,30.58]}},{"type":"Feature","properties":{"序号":6.0,"姓名":"王 珪","朝代":"北宋","籍贯(原名)":"华阳县","籍贯(现代)":"成都双流区","经度":103.93,"纬度":30.58,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[103.93,30.58]}},{"type":"Feature","properties":{"序号":7.0,"姓名":"王仲甫","朝代":"北宋","籍贯(原名)":"华阳县","籍贯(现代)":"成都双流区","经度":103.93,"纬度":30.58,"简介":"字明之，珪从子。曾官主簿，客居吴门。事见《中吴纪闻》卷四。","主要作品":"今存词七首。"},"geometry":{"type":"Point","coordinates":[103.93,30.58]}},{"type":"Feature","properties":{"序号":8.0,"姓名":"王仲修","朝代":"北宋","籍贯(原名)":"华阳县","籍贯(现代)":"成都双流区","经度":103.93,"纬度":30.58,"简介":"王珪子。熙宁三年（1070年）进士，（《攻媿集》卷七五《跋王岐公端午帖子》）。以著作佐郎为崇文院校书，同知太常礼院（《宋会要辑稿》选举三三之一四）。元丰四年，以谒告淮南行为不检，冲替（同上书职官六六之一五）。元祐二年，勒停（《续资治通鉴长编》卷四〇一）。其父王珪因议建储事，坐追贬万安军司户参军，元符三年（1110年），王仲修为诉冤曲，乃尽复故官赠谥。事迹见《东都事略》卷八〇、《宋诗纪事》卷二九。","主要作品":"《宫词》等诗一〇二首，收入宋刻本《四家宫词》。《全宋诗》卷八七六录其诗一卷。?《全宋文》卷二五二八收其文一篇。"},"geometry":{"type":"Point","coordinates":[103.93,30.58]}},{"type":"Feature","properties":{"序号":9.0,"姓名":"朱休","朝代":"唐","籍贯(原名)":"剑南","籍贯(现代)":"成都市（泛称）","经度":104.07,"纬度":30.58,"简介":"以能赋有名于太学。归剑南时，贾岛作诗相送。事迹据《长江集》卷八《送朱休归剑南》考知。","主要作品":"五言排律《春水绿波》1首及辞赋《驾幸太学赋》1篇，其"},"geometry":{"type":"Point","coordinates":[104.07,30.58]}},{"type":"Feature","properties":{"序号":10.0,"姓名":"宇文价","朝代":"北宋","籍贯(原名)":"成都县","籍贯(现代)":"成都市","经度":104.07,"纬度":30.58,"简介":"隆兴元年（1163）进士。以善治诗赋知名于世。乾道三年（1167），除秘书郎。四年（1168），擢著作佐郎，寻改起居舍人。淳熙间，累迁兵部尚书，后出知遂宁府，徙襄阳府。善属文。《四川通志》有传。","主要作品":"《宋代蜀文辑存》录其文十五篇。"},"geometry":{"type":"Point","coordinates":[104.07,30.58]}},{"type":"Feature","properties":{"序号":11.0,"姓名":"李余","朝代":"唐","籍贯(原名)":"成都县","籍贯(现代)":"成都市","经度":104.07,"纬度":30.58,"简介":"唐文宗大和七年(833)癸丑科状元及第。该科进士及第二十五人。考官：礼部侍郎贾餗。取状元后归省，友人贾岛、姚合、朱庆余等人赋诗话别。后不知所终。李余工乐府诗。","主要作品":"《全唐诗》有其存诗二首。"},"geometry":{"type":"Point","coordinates":[104.07,30.58]}},{"type":"Feature","properties":{"序号":12.0,"姓名":"尹鹗","朝代":"唐","籍贯(原名)":"成都县","籍贯(现代)":"成都市","经度":104.07,"纬度":30.58,"简介":"约唐昭宗乾宁中前后在世。事前蜀后主王衍，为翰林校书。累官至参卿。《花间集》称尹参卿，性滑稽，工诗词，与李珣友善，作风与柳永相近。","主要作品":"今存词十七首。词存《花间集》、《尊前集》中。今有王国维辑《尹参卿词》一卷。"},"geometry":{"type":"Point","coordinates":[104.07,30.58]}},{"type":"Feature","properties":{"序号":13.0,"姓名":"梅 挚","朝代":"北宋","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":14.0,"姓名":"勾 涛","朝代":"北宋","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":15.0,"姓名":"杨 慎","朝代":"明","籍贯(原名)":"新都县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":16.0,"姓名":"杨宗吾","朝代":"明","籍贯(原名)":"新都县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"杨慎之孙。明神宗时在世。官锦衣卫指挥，与宦官共事，宦官骄横，宗吾屡次上疏弹劾。开矿中州（今河南一带），后因怜民劳苦，抗章求罢，祸几不测，然中州人甚感其惠。《四川通志》有传。","主要作品":"著有《检橐随笔》三十卷，分二十四类，采掇事实，分条编载，体近类书。其中丽句、琐语两类，则专取诗文辞藻。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":17.0,"姓名":"费经虞","朝代":"明","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"，字仲若，号鲜民，门人私谥“孝贞先生”。费密父。崇祯十二年（1639）举人，十七年（1644）受昆明知县，薄征省讼，重士劝农，勘覆吾必奎叛党案及娠济云南灾民，活民数万。迁云南府同知，是时因蜀大乱，请归不得。后剃发以示必返，乃许，辗转流寓扬州，闭门纂述。他博学能诗，著述甚丰。","主要作品":"有《毛诗广义》、《四书字义》、《古今方书》、《周易参同契合注》、《临池能训》、《字学》、《四书鼓训》、《古韵拾遗》、《荷衣集》、《雅伦》等行世。又与其子费密共辑《剑阁芳华集》二十卷。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":18.0,"姓名":"费密","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"明末清初著名学者、诗人和思想家。字此度，号燕峰，四川新繁人。费经虞子。奉父流寓泰州，其父邃于经学，尽传父业，工诗文，究心兵农礼乐等学，以教授、卖文为生，当道拟举鸿博，荐修《明史》，皆为辞。费密守志穷理，讲学著述，在文学、史学、经学、医学、教育和书法等方面都有很高的造诣。费密与遂宁吕潜、达川唐甄合称“清初蜀中三杰”。后代学者评论说：“蜀中自杨升庵外，唯密著作最富，论说精辟，对后世颇有影响”。子锡琮、锡璜，皆能文。","主要作品":"【朝天峡】"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":19.0,"姓名":"费锡璜","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"字滋衡。费密次子。豪放不羁，自伤怀才不遇，尝登之罘，投其诗于海中，痛哭而返。其诗古体直接汉魏，近体追踪盛唐。","主要作品":"《掣鲸堂诗集》"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":20.0,"姓名":"杨宏绪","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"康熙五十年（1711）举人。六十年（1721）进士。授河南彰德府汤阴县知县。值岁荒歉，请开仓赈□贫民，鬻妻女者，出俸钱赎之复还。给河夫口粮，冬捐赠棉衣，惠政颇多。父殁，归里居丧。服除，补河南尉氏县知县，兼洧川知县。尉氏多盗，号称难治。宏绪莅任，则力行保甲，擒盗魁神手张八，境内为之宴然。洧川狱中系囚百余人，瘟疫大作，为遣医护视，昼夜清理案牍，审查判决，株连者皆释去，罪轻者交保，囹圄一清。河东总督田文镜奇其才，奏擢福建福州府知府。旋调汀漳驿盐道，所至有能名。雍正十三年（1735）擢浙江按察使。先是浙省案牍殷繁。囚犯不即讯，吏胥因缘为奸，羁留需索，民大受其害。宏绪设锣于门，许囚至鸣锣以闻，随至随鞫，持法平允，吏不能欺。后以事挂误，左迁湖南储粮道，病卒于任。宏绪工文章，长诗赋。《四川通志》、《锦里新编》有传。","主要作品":"著有《直养斋文集》六卷、《直养斋诗集》四卷行世。孙桐生《国朝全蜀诗钞》、徐世昌《晚晴诗汇》录有其诗。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":21.0,"姓名":"张宏仁","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"曾祖明宇，以武职官汉中府都司。宏仁素敦孝友，姿性尤敏。少师举人傅□言，为文隽异，弱冠即补弟子员。时闽中郑方城为新繁令，宏仁受业于其子，诗古文词俱有宗法。乾隆十五年（1750）举人，二十二年（1757）进士。授直隶临城县知县。三十四年（1769）捕获山西重犯□生玉，以功升安徽颍州府知府。《四川通志》有传。","主要作品":"著有《二楠堂集》。《新繁文征》录有其诗。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":22.0,"姓名":"张谨度","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"乾隆五十四年（1789）拔贡。朝考一等二名，试贴为高宗所赏识，批云：“诗冠天下。”自此诗名大噪。授四川南川县教谕，母丧归里。服除，补陕西石泉县教谕。石泉偏僻，民多质野。谨度集诸生朝夕讲授，又劝邑人于乡堡间立学，由是文风一振。为教谕三十余年，造士皆众。道光初擢顺天府（今南充市）教授。未几，以截取铨直隶保定府定兴县知县。以忤布政使屠某，改阜平。旋罢官。归田后，绝迹尘事，教授诸生及其孙，故其孙汝玉、汝珏均工诗文，善书画，有祖风，为邑名士。谨度年七十八卒于家。《新繁县志》有传。","主要作品":"著有《唾余诗草》行世。《新繁文征》录有其诗。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":23.0,"姓名":"谢子澄","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"道光十二年（1832）举人。大挑一等，拣发知县。历官直隶青县、静海、邯郸、卢龙、滦州、无极等县。所至皆有惠政。咸丰三年（1852）调天津，论疏运道功，擢直隶州知州，留视县事。时太平天国义军由河南进攻山西、河北，子澄募津勇三千余人拒之，战死。子澄工诗，《新都县志》有传。","主要作品":"徐世昌《晚晴诗汇》录有其诗。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":24.0,"姓名":"姜兆璜","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":105.17,"纬度":31.83,"简介":"道光乙酉科拔贡任中江安县字渔生，四川新繁人，清代官员。道光五年（1825年）拔贡，曾任江安教谕。年三十\n以抑郁卒。","主要作品":"著有《梦橘堂诗草》"},"geometry":{"type":"Point","coordinates":[105.17,31.83]}},{"type":"Feature","properties":{"序号":25.0,"姓名":"魏用之","朝代":"清","籍贯(原名)":"新都县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"道光二十年（1840）举人。赴京会试，值粤乱起，海内骚然，用之虑贻亲忧，不试而归家奉亲。母殁，移榻与父共一室者十五年。同治五年（1866）卒于家。《新都县志》有传。","主要作品":"著有《新都水利考》一卷、《读史论略》四卷、《有所思轩诗草》一卷。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":26.0,"姓名":"杨益豫","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"工诗文，善书画。咸丰九年（1859）举人。同治元年（1862），进士。选翰林院庶吉士，寻授工部主事。九年（1870），周谓臣督师黔中，邀益豫主管军中文书。母逝，归里服丧，主讲繁江书院。四川总督吴棠修省志，延益豫襄其事。光绪五年（1879）服除回京，改补甘肃靖远县知县。同城副将多贪纵，益豫严正训斥，故胥吏无敢干以私者。其平狱惠民，兴学课士，有古循吏风。旋卒于任。《新繁县志》、《益州书画录》有传。","主要作品":"著有《停琴寄笠山房诗集》十五卷、《停琴寄笠山房文集》十四卷、《奇男子遗事》一卷、《立生随笔》十二卷、《杂记》六卷、《故事摭余》一卷、《掷虚杂言》一卷、《书画记》一卷、《余屑》一卷、《程余质谈》二卷、《工部笔谈》四卷。又同高瀛合纂《[同治]新繁县志》十六卷。《新繁文征》录有其诗。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":27.0,"姓名":"姚桐生","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"懋纲之孙。桐生幼承祖训，聪慧嗜学。同治六年（1867）举人。再经朝考，学行卓异，授咸安宫教习。旋归蜀，官松潘厅教授，任满，主讲繁江书院。光绪十二年（1886）进士。授礼部主事，后改铨知县，任职江苏吴县。莅任月余而卒。桐生又工书法。《新繁县志》、《益州书画录》有传。","主要作品":"善诗古文辞，存稿多佚，唯《还蜀诗钞》行世。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":28.0,"姓名":"谢济勋","朝代":"清","籍贯(原名)":"新繁县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"性孝友，亲殁，庐墓居丧三年。妻周氏卒，终身不娶。人以此称之。善诗文，尤精经学。尝云：“新当世民吾弗能，新后世民可也。”同治十三年（1874）张之洞督学四川，深赏其文，叹为“真读书人”。《新繁县志》有传。","主要作品":"著有《周易象图》一卷、《周易上下经学》十卷、《系辞传说卦传序卦传杂卦传说》十卷、《尚书经义》、《诗经序义证》、《孝经述》、《论语义述》、《大学定本述》、《中庸释》、《新繁清韵》、《论孟刍言略说》各一卷、《论孟刍言详说》七卷、《好古敏求斋诗文集》二十卷行世。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":29.0,"姓名":"温永恕","朝代":"清","籍贯(原名)":"新都县","籍贯(现代)":"成都新都区","经度":104.17,"纬度":30.83,"简介":"同治十二年（1873）举人。开学馆于成都，一时从游之士，多有掇巍科登高第者，有“小锦江”之称。其时主锦江书院者，为垫江李惺。惺乃名进士，并以文章显于当时，蜀中之士半出其门。故有是说。惺亦雅重永恕，时人两贤之。永恕尤能睦族，遇族嫠妇之贫不能自存者，时分其束修所得金□恤之。卒年七十三岁。《新都县志》有传。","主要作品":"著有《春秋经传节录》、《南华经浅注》、《来瞿塘先生目录评语》等六种。"},"geometry":{"type":"Point","coordinates":[104.17,30.83]}},{"type":"Feature","properties":{"序号":30.0,"姓名":"张吾瑾","朝代":"清","籍贯(原名)":"金堂县","籍贯(现代)":"成都金堂县","经度":104.42,"纬度":30.83,"简介":"工诗文，精医术。顺治十一年（1654）举人。联捷进士。授山东夏津县知县，倡修学宫、文昌祠，又捐俸整修许门楼，建四门桥。为官清廉，持正不阿。凡有诉讼，折狱如神。内擢行人。两充山东乡试同考官，得士颇多。德州司农田雯、武清中丞李炜皆出其门。致仕后，因蜀乱居武清（今属天津市）二十载，年七十始归里。时都江堰年久失修，毁决为害。吾瑾多次呈状，力请上官整治，重修三泊洞古堤，里人颂德。后卒于家。邑人崇祀乡贤祠。《四川通志》、《锦里新编》有传。","主要作品":"著有《人镜经续录》二卷、《鹊符斋诗文集》四卷。另辑有《和薛涛诗集》。李调元《蜀雅》、孙桐生《国朝全蜀诗钞》录有其诗。"},"geometry":{"type":"Point","coordinates":[104.42,30.83]}},{"type":"Feature","properties":{"序号":31.0,"姓名":"张晋生","朝代":"清","籍贯(原名)":"金堂县","籍贯(现代)":"成都金堂县","经度":104.42,"纬度":30.83,"简介":"父吾瑾，顺治十二年（1655）进士，官至行人，著有《鹊符斋集》。晋生幼承父训，勤奋读书，博通经史。康熙四十一年（1702）举人。历官河南镇平县知县，有政声。致仕归。雍正间与修《四川通志》。掌教锦江书院，艺林推重。《四川通志》有传。","主要作品":"著有《摅怀集》、《时术堂文集》、《锦江书院存稿》行世。李调元《蜀雅》、孙桐生《国朝全蜀诗钞》录有其诗。"},"geometry":{"type":"Point","coordinates":[104.42,30.83]}},{"type":"Feature","properties":{"序号":32.0,"姓名":"余鸿观","朝代":"清","籍贯(原名)":"金堂县","籍贯(现代)":"成都金堂县","经度":104.42,"纬度":30.83,"简介":"性嗜学，家贫无力购书，尝售已读书易未读书。书贾器而怜之，愿以异书易之，不名一钱。同治十三年（1874）补县学生员。嗣是凡岁科试，辄列高等。旋调入成都尊经书院上舍。五与乡试不第，亦不以为意。乡里耆旧争延为师，从学者以百数，中举者甚多。久而名益噪，士大夫争欲致之幕下。初随进士钱铁江衡文什邡；继随进士赵达泉衡文中江。所至甄拔宿儒，周览山水。又以其胸中磅礴抑郁之气，发而为诗歌，传诵一时。光绪十八年（1892）以明经注选训导。二十六年（1900）任夹江县训导。三十二年（1906）五月卒于家，年六十一岁。《续金堂县志》有传。","主要作品":"著《蜀燹述略》四卷、《养松塾言》一卷，收入省采访局。"},"geometry":{"type":"Point","coordinates":[104.42,30.83]}},{"type":"Feature","properties":{"序号":33.0,"姓名":"扬雄","朝代":"汉","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":"又作杨雄，字子云，蜀郡成都（成都郫县友爱镇?[21]）人。名士严君平弟子，庐江太守扬季五世孙。中国西汉末年哲学家、文学家、辞赋家、思想家。","主要作品":"《子虚赋》、《上林赋》，作《甘泉赋》、《羽猎赋》、《长杨赋》等"},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":34.0,"姓名":"杜琼","朝代":"汉","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":"字伯瑜，杜琼学识渊博、沉默少言，自幼时跟随任安学习，是三国时期著名学者。\n杜琼不仅精通经纬术艺，同时也精通天文占验，曾与谯周论说天文，并肯定了“当涂高者魏也”的预言，解释了其中的原因。250年（延熙十三年），杜琼去世，著有。","主要作品":"《韩诗章句》"},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":35.0,"姓名":"张俞（愈）","朝代":"北宋","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":"北宋文学家。字少愚，又字才叔，号白云先生，益州郫（今四川郫县）人，祖籍河东（今山西）。屡举不第，因荐除秘书省校书郎，愿以授父而自隐于家。文彦博治蜀，为筑室青城山白云溪。","主要作品":"著有《白云集》，已佚。"},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":35.0,"姓名":"张俞（愈）","朝代":"北宋","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":"屡举不第，于宋仁宗宝元（1038年-1040年）初，曾上书言边事。后隐居于岷山白云溪，朝廷多次征召，均不起。其喜游山水，游历天下三十馀年，后闭门著书，未就而卒。其妻诔之曰：“穷亦自固，困亦不颠。不贵人爵，知命乐天。”张俞为文有西汉风，苏舜钦曾赞其《洛阳怀古赋》。张俞的诗多为遨游山水之作。其《蚕妇》一首：“昨日入城市，归来泪满巾。遍身罗绮者，不是养蚕人。”传诵久远，为世所重。《郡斋读书志》著录其《白云集》三十卷，《宋史·艺文志》著录《张俞集》二十六卷，今已不传。《东都事略》卷一一八， 《宋史》卷四五八有传。","主要作品":"有《白云集》。"},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":36.0,"姓名":"张午","朝代":"南宋","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":37.0,"姓名":"许儒龙","朝代":"清","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":"美丰仪。少负才名。乾隆元年（1736），以博学鸿词科徵计偕入都试而被放。遂遍游大江南北。由武夷山返棹归里。先人旧庐，筑野园，起亭台。日究研经史，吟啸其中。与彭端淑兄弟、蔡时田兄弟为文字之交。年八十三卒于家。《四川通志》、《锦里新编》有传。","主要作品":"儒龙工诗文，著有《水南诗集》、《岷南诗草》八卷行世。毛振□为之序。李调元《蜀雅》、孙桐生《国朝全蜀诗钞》、徐世昌《晚晴诗汇》录有其诗。"},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":38.0,"姓名":"孙錤","朝代":"清","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":"清文学家。字野史,号独学生,又号岷阳大布衣。郫县(今属四川)人。嘉庆时国学生。不求举业,与其弟创“古棠书屋”肆力著述。","主要作品":"著有《瘦石文钞》、《瘦石诗集》、《蜀破镜》等。"},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":39.0,"姓名":"卫道凝","朝代":"清","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":"乾隆五十一年（1786）乡试解元。五赴京试皆落第，退而讲身心性命之学，精于考据。历主岷江、崇阳、八旗书院，所在皆有著述。嘉庆二十二年（1817）考选一等，补南江县训导。道光三年（1823）卒于任，年六十二岁。《郫县志》有传。","主要作品":"著有《补注大常朝践礼》一卷、《杨子云蜀都赋注解》、《蜀编年志》、《忠谠遗音》二卷、《桤园草》、《谨读篇》二卷、《六经精义》、《周易集注》六卷，《春秋传举要》、《金川经闻》一卷、《敬信录》、《诸子精醇》、《桤园诗集》刊行。"},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":40.0,"姓名":"余燮枢","朝代":"清","籍贯(原名)":"郫县","籍贯(现代)":"成都郫都区","经度":103.91,"纬度":30.8,"简介":"清末附贡生。励志读书，素有用世志，补学官弟子，一试秋闱不利，入资捐州判，继以同知诣云南蒙姑收税。后署广西州（治所在今云南泸西县）知州。适巧家为乱，燮枢募乡勇平之。大府上其功，加一级以知府用。燮枢与滇司马龙沛然皆跌宕自许，各有政声于时，过从甚密，诗酒流连。丁父忧归，遂不复出。事母以孝闻。颜所居曰“□园”。艺菊种荷，拥书万卷，萧然有尘外之致。好琴工诗，兼通医术。晚年自号“岷阳老樵”。刻私印曰“烟瘴余生”。卒于彭县天台山万寿寺。《郫县志》有传。","主要作品":"著有《园诗集》二卷、《园文集》一卷、《训子遗篇》一卷。"},"geometry":{"type":"Point","coordinates":[103.91,30.8]}},{"type":"Feature","properties":{"序号":41.0,"姓名":"花蕊夫人","朝代":"五代","籍贯(原名)":"灌县","籍贯(现代)":"成都都江堰市","经度":103.65,"纬度":30.99,"简介":"后蜀主孟昶的费贵妃，五代十国女诗人，青城（今都江堰市东南）人。幼能文，尤长于宫词。得幸蜀主孟昶，赐号花蕊夫人。其宫词描写的生活场景极为丰富，用语以浓艳为主，但也偶有清新朴实之作，如“三月樱桃乍熟时，内人相引看红枝。回头索取黄金弹，绕树藏身打雀儿”这一首，就写得十分生动活泼，富有生活情趣；其《述国亡诗》亦颇受人称道，实难得之才女也。。","主要作品":"《述国亡诗》\n诗一（《全唐诗》下卷第七百九十八）"},"geometry":{"type":"Point","coordinates":[103.65,30.99]}},{"type":"Feature","properties":{"序号":42.0,"姓名":"杨朝英","朝代":"元","籍贯(原名)":"灌县","籍贯(现代)":"成都都江堰市","经度":103.65,"纬度":30.99,"简介":"字英甫，号澹斋，青城人，元代散曲家，曾任郡守、郎中，后归隐。与贯云石、阿里西瑛等交往甚密，相互酬唱，时人赞为高士。他们情趣相投，常在一起评论当时的散曲创作，贯云石为杨朝英编选的我国元代第一部散曲集《乐府新编阳春白雪》作序。","主要作品":"选录元人散曲，辑为《乐府新编阳春白雪》《朝野新声太平乐府》二集，人称“杨氏二选”。"},"geometry":{"type":"Point","coordinates":[103.65,30.99]}},{"type":"Feature","properties":{"序号":43.0,"姓名":"虞堪","朝代":"元","籍贯(原名)":"灌县","籍贯(现代)":"成都都江堰市","经度":103.65,"纬度":30.99,"简介":"元末明初在世。堪流寓长洲（今江苏苏州市），多次返蜀。喜作诗，尤多题画之作。《四川通志》有传。","主要作品":"著有《希澹园诗》三卷，多忧时感事之言。古体气格颇高，近体亦音节谐婉，无当时浓艳之习，可谓娟娟独立。"},"geometry":{"type":"Point","coordinates":[103.65,30.99]}},{"type":"Feature","properties":{"序号":44.0,"姓名":"赵彦呐","朝代":"南宋","籍贯(原名)":"彭县","籍贯(现代)":"成都彭州市","经度":103.97,"纬度":31.0,"简介":"少以材称。宋宁宗开禧时，中四川类省试第一。吴曦作乱，伪命禄禧守夔州，彦呐因结义士杀之，遂显名。嘉定十二年（1219），金兵入侵关外西和州（今甘肃西和），制置使安丙檄彦呐前往经理，乃奋战却敌。因请修州北水关，募民耕战以守；又劝丙尽捐关外四州租，结民兵使各自为守。越五年，转提点刑狱，寻帅沔州。理宗宝庆元年（1225），移帅兴元府，后罢归。绍定四年（1231），起为利州路安抚副使。史嵩之奏留江陵，两年后卒。《宋史》、《南宋书》有传。","主要作品":"彦呐能诗，《宋诗纪事补遗》录其诗一首。"},"geometry":{"type":"Point","coordinates":[103.97,31.0]}},{"type":"Feature","properties":{"序号":45.0,"姓名":"赵司铉","朝代":"明","籍贯(原名)":"彭县","籍贯(现代)":"成都彭州市","经度":103.97,"纬度":31.0,"简介":"，崇祯三年（1630）举人。负经济才。蜀乱，以智自全。王应熊在川时以为军政官，授越抚夷同知。李乾德经略六省时，奏补建昌道兵备佥事。卒于重庆。《四川通志》有传。","主要作品":"时人以其诗有王孟遗意，《蜀明诗》录《越寒食感怀》及《拜将坛和费此度韵》二首，可见一斑。晚岁以俚调作警世语，名《淡淡篇》。"},"geometry":{"type":"Point","coordinates":[103.97,31.0]}},{"type":"Feature","properties":{"序号":46.0,"姓名":"杨岱","朝代":"清","籍贯(原名)":"彭县","籍贯(现代)":"成都彭州市","经度":103.97,"纬度":31.0,"简介":"康熙三十五年（1696）举人。官福建上杭县知县。有贤声。著有《山诗集》，潘稼堂为之序，称其诗“高华爽朗，有和平蔼吉之风，无刻削纤琐之习。”岱与其弟□、岐俱以诗名，士林称为“彭县三杨”。“而东子诗尤娇娇特出，如百战健儿，三鼓而气不竭。”《四川通志》、《锦里新编》有传。","主要作品":"著有《山诗集》。（张邦伸《锦里新编》卷五）沈德潜《清诗别裁集》、李调元《蜀雅》、孙桐生《国朝全蜀诗钞》、徐世昌《晚晴诗汇》录有其诗。"},"geometry":{"type":"Point","coordinates":[103.97,31.0]}},{"type":"Feature","properties":{"序号":47.0,"姓名":"杨崑","朝代":"清","籍贯(原名)":"彭县","籍贯(现代)":"成都彭州市","经度":103.97,"纬度":31.0,"简介":"善诗，著有《三树堂诗集》。李调元《雨村诗话》云：“人皆知丹□有三彭，而不知先有三杨。一杨岱，字东子，康熙丙子举人，有《山集》；一岐，字周子，有《碧萝亭集》；一□，字葛山，有《三树堂集》。皆以诗名，……三彭以科名显，而三杨仅一孝廉，故人多不传，其实能诗不系名利也，世有能诗而不第者岂少哉。”张邦伸云：“杨氏昆仲，矫矫者东子。此外则葛山，亦俨然成家。”《四川通志》、《锦里新编》有传。","主要作品":"李调元《蜀雅》、孙桐生《国朝全蜀诗钞》录有其诗。"},"geometry":{"type":"Point","coordinates":[103.97,31.0]}},{"type":"Feature","properties":{"序号":48.0,"姓名":"刘泾","朝代":"北宋","籍贯(原名)":"简州","籍贯(现代)":"成都简阳市","经度":104.55,"纬度":30.42,"简介":"字巨济，号前溪，宋代画家、词人。熙宁六年（1073年）进士，官至职方郎中，历任提举修撰经义所检讨、太学博士、国子监丞及多地知州。其书画以林石槎竹见长，笔墨风格狂逸拔俗，与米芾、苏轼为书画挚友，成都太智院法堂存有其松竹画壁。刘泾中进士后负责修订太学教材。元祐元年（1086年）罢太学博士知咸阳县，后任常州教授、通判莫州等职。元符末年召对授职方郎中，同年逝世。晚年专事书画创作，苏轼评其书法“细书千纸杂真行”。","主要作品":"著有《前溪集》《西汉发挥》等文集，《全宋词》录存其词作二首，其中《夏初临·夏景》描绘立夏景致。现存诗作22首涵盖多种体裁，词作《夏初临》以立夏为题。"},"geometry":{"type":"Point","coordinates":[104.55,30.42]}},{"type":"Feature","properties":{"序号":49.0,"姓名":"曾国光","朝代":"清","籍贯(原名)":"简州","籍贯(现代)":"成都简阳市","经度":104.55,"纬度":30.42,"简介":"幼颖悟过人，过目成诵。喜吟咏，每有感触，辄成篇章。弱冠举茂才。嘉庆二十一年（1816）举人。开塾授徒，每于讲授-帖括外，即谆谆以声律为课。门下士如段凤仪、陈治安、黄裳吉等，皆相继著称于时。道光二年（1822）春闱下第，遂馆都中。四年（1842）四月病卒。《简阳县志》有传。","主要作品":"著有《耕雨堂诗钞》，垫江李惺为之序。"},"geometry":{"type":"Point","coordinates":[104.55,30.42]}},{"type":"Feature","properties":{"序号":50.0,"姓名":"吴大光","朝代":"清","籍贯(原名)":"简州","籍贯(现代)":"成都简阳市","经度":104.55,"纬度":30.42,"简介":"父德汉并赠奉政大夫。大光少承庭训，好学不辍。入州庠后，补增生。尝从易尧堂、胡仁至游，学业大进。咸丰九年（1859）举人。同治元年（1862）进士。改官宁远府教授，以襄办夷务功，加盐道提举衔。郡中士多僻陋，大光掌教泸峰书院十余年，力挽其习，士民感德。后卒于家，年八十四岁。《简阳县志》有传。","主要作品":"著有《纪游草》二卷、《建南杂录》八卷行世。"},"geometry":{"type":"Point","coordinates":[104.55,30.42]}},{"type":"Feature","properties":{"序号":51.0,"姓名":"徐树棠","朝代":"清","籍贯(原名)":"简州","籍贯(现代)":"成都简阳市","经度":104.55,"纬度":30.42,"简介":"家素贫，年十二即出外训蒙。年二十三入州学，旋补增生。咸丰元年（1851）举人。晚掌凤山书院，从游甚众。树棠制艺鸣一时，兼工散文联语。后卒于家。《简阳县志》有传。","主要作品":"著有《少岩文集》二卷、《廿二史考鉴录》录二十六卷行世。"},"geometry":{"type":"Point","coordinates":[104.55,30.42]}},{"type":"Feature","properties":{"序号":52.0,"姓名":"萧刘氏","朝代":"清","籍贯(原名)":"富顺县","籍贯(现代)":"自贡富顺县","经度":104.98,"纬度":29.19,"简介":"以诗名。其夫参将萧某戌黎州、雅州、刘氏亦流寓滇南。闻南明永历帝走缅，乱兵将至，自知不免。乃将七岁子付家奴，远适夫所。与其女俱自经死。《锦里新编》、《富顺县志》有传。","主要作品":"死前题诗于壁，以“驿梅惊别意堤柳暗离愁”十字，为诗十首，各拆一字，号离合体。有“心怜夫嗣儿还父，意惨君仇女伴娘”，“士兵劫去又官兵，日望征人不复生”，“日前送别唱阳关，立石望夫还未还”，“音信频从陇外寄，暗传汝妇已投缳”等句，颇凄婉感人。"},"geometry":{"type":"Point","coordinates":[104.98,29.19]}},{"type":"Feature","properties":{"序号":53.0,"姓名":"范璐","朝代":"清","籍贯(原名)":"富顺县","籍贯(现代)":"自贡富顺县","经度":104.98,"纬度":29.19,"简介":"字与石，司马矿子，康熙壬子乡试第三，博学能文。直吴逆取士云南，璐不应试，仕宜君县令。","主要作品":"著有《葛山诗集》。"},"geometry":{"type":"Point","coordinates":[104.98,29.19]}},{"type":"Feature","properties":{"序号":54.0,"姓名":"李九霞","朝代":"清","籍贯(原名)":"富顺县","籍贯(现代)":"自贡富顺县","经度":104.98,"纬度":29.19,"简介":"字饮仙，尔振子。康熙甲午副榜，仕巴县教谕。幼颖异，读书不事呫毕，辄晓大旨。工诗，洒翰立成，性尤刚直。为教谕时，郡守张欲取诸生，陈某赂未遂，移牒学中，取该生入学年分，九霞难之。旁观谓守素骄贵，不送申，恐祸不测。九霞究坚执不允，守因他事卸任，遂寝。后守顾贽重其学品，保举卓荐，旋卒。","主要作品":"著有《卓山诗文二集》。"},"geometry":{"type":"Point","coordinates":[104.98,29.19]}},{"type":"Feature","properties":{"序号":55.0,"姓名":"熊 过","朝代":"明","籍贯(原名)":"富顺县","籍贯(现代)":"自贡富顺县","经度":104.98,"纬度":29.19,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.98,29.19]}},{"type":"Feature","properties":{"序号":56.0,"姓名":"许沆","朝代":"南宋","籍贯(原名)":"泸州","籍贯(现代)":"泸州江阳区","经度":105.44,"纬度":28.88,"简介":"南宋时累官至太府少卿。性至孝，该博能文，亦工诗。每与同里史扶往来酬唱，俱以诗名世，时号泸南诗老《蜀中广记?著作》有载，《四川通志》有传。","主要作品":"。著有《奏议》、《许沆文集》三十卷，均佚。"},"geometry":{"type":"Point","coordinates":[105.44,28.88]}},{"type":"Feature","properties":{"序号":57.0,"姓名":"先著","朝代":"明","籍贯(原名)":"泸州","籍贯(现代)":"泸州江阳区","经度":105.44,"纬度":28.88,"简介":"明天启至清康熙年间在世。张献忠入蜀，流寓淮南，后又侨居金陵。与大江南北诸名士来往唱酬无虚日。著博览多闻，尤工诗词。张邦伸《锦里新编》云：“沈归愚《国朝诗别裁》所选十数篇，皆戛戛独造，高出时流。然片羽吉光，犹不足尽箧中之宝也。”李调元《蜀雅》谓：“渭求诗造句必新，遣言必雅。亦词坛飞将也。”徐世昌《晚晴诗汇》则谓其“诗多警语”、“名句”。著又善画花卉、人物，极有法度。《益州书画录》、《四川通志》有传。","主要作品":"著有《之溪老生诗集》、《劝影堂词》三卷、《词评》一卷，又与程洪合辑《词洁集》八卷行世。张应昌《清诗铎》、孙桐生《国朝全蜀诗钞》亦均录有其诗。叶恭绰《全清词钞》录有其词。"},"geometry":{"type":"Point","coordinates":[105.44,28.88]}},{"type":"Feature","properties":{"序号":58.0,"姓名":"张学古","朝代":"清","籍贯(原名)":"泸州","籍贯(现代)":"泸州江阳区","经度":105.44,"纬度":28.88,"简介":"工诗文，善书画。秋试屡诎，乃出资捐教职。历署苍溪、长宁、广元训导，忠州（今忠县）学正，保宁府（今阆中县）教授。咸丰二年（1852）署达县训导，遂家于达县翠屏乡镜潭庄。生平不治产业。性廉介，例输院费皆却不受。解官后，晚年家益落，除卖诗文书画外，一无所取。后卒于家。学古诗、书、画皆力追遂宁张船山。曾题诗达县石桥辅，为四川学使何绍基所赏识，出扇命书，诗书俱佳，叹为船山复生。其零缣断纸，流落人间者，皆视若拱璧。《益州书画录》有传。","主要作品":"著有《闲闲草》、《白岩存稿》行世。《泸县志》录有其文。"},"geometry":{"type":"Point","coordinates":[105.44,28.88]}},{"type":"Feature","properties":{"序号":59.0,"姓名":"万 慎","朝代":"清末民初","籍贯(原名)":"泸州","籍贯(现代)":"泸州龙马潭区","经度":105.44,"纬度":28.92,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[105.44,28.92]}},{"type":"Feature","properties":{"序号":60.0,"姓名":"李化楠","朝代":"清","籍贯(原名)":"罗江县","籍贯(现代)":"德阳罗江区","经度":104.52,"纬度":31.32,"简介":"字廷节，号石亭、让斋。四川绵州罗江县（今）人，清代文学家，罗江乡贤，绵州名儒，浙江循良，京师“强项令”，殉于名节。乾隆七年（1742）进士，历官浙江余姚知县、秀水知县兼署平湖知县事，直隶沧州、涿州知州，天津府海防同知，霸州、蓟州知州，宣化府、顺天府同知。为反贪殉于名节。生平行事及其成就载清嘉庆《四川通志》、嘉庆《罗江县志》。","主要作品":"著有《石亭文集》6卷，《石亭诗集》10卷，《醒园录》2卷。"},"geometry":{"type":"Point","coordinates":[104.52,31.32]}},{"type":"Feature","properties":{"序号":61.0,"姓名":"李调元","朝代":"清","籍贯(原名)":"罗江县","籍贯(现代)":"德阳罗江区","经度":104.52,"纬度":31.32,"简介":"清代著名文学家、诗人、剧作家、藏书家，字羹堂，号雨村。乾隆二十八年（1763）李调元进士及第，钦点为翰林庶吉士，授予吏部文选司主事，之后还担任过广东乡试副考官、考功员外郎、广东学政。乾隆五十年（1785）遭诬罢职回到四川，归隐于醒园。","主要作品":"李调元一生著述宏伟，内容涉及广泛，代表作有《李调元诗集》、《雨村诗话》、《雨村词话》，刊印《函海》、《续函海》、《蠢翁词》等异于前人佳作，别具一格。"},"geometry":{"type":"Point","coordinates":[104.52,31.32]}},{"type":"Feature","properties":{"序号":62.0,"姓名":"李鼎元","朝代":"清","籍贯(原名)":"罗江县","籍贯(现代)":"德阳罗江区","经度":104.52,"纬度":31.32,"简介":"，字味堂，一字和叔，号墨庄，四川绵州人。乾隆四十三年（1778年）进士，改庶吉士，授翰林院检讨。与兄弟李调元、李骥元同称“绵州三李”。嘉庆五年（1800年）与赵文楷出使琉球，五月初一登舟，并作“航海词”。官至兵部主事。","主要作品":"著有《使琉球记》六卷、《再游记》四卷。"},"geometry":{"type":"Point","coordinates":[104.52,31.32]}},{"type":"Feature","properties":{"序号":63.0,"姓名":"李骥元","朝代":"清","籍贯(原名)":"罗江县","籍贯(现代)":"德阳罗江区","经度":104.52,"纬度":31.32,"简介":"字凫塘，号云栈，书法以赵文敏为宗。生平事迹见《清史列传》卷七二本传，孙桐生《国朝全蜀诗钞》，清嘉庆二十年《罗江县志》卷三十六李调元《李骥元传》。","主要作品":"著有《云栈诗稿》"},"geometry":{"type":"Point","coordinates":[104.52,31.32]}},{"type":"Feature","properties":{"序号":64.0,"姓名":"王隐君","朝代":"五代","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"十国春秋，中江人。抱道不仕，尤工于诗。有《落花吟》诗。云“富贵雨中花，昨开今复落。无人解花意，俱为贪花错。”\n盖有感于时事，志在远引故，姓名不传。","主要作品":"《落花吟》诗"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":65.0,"姓名":"苏易简","朝代":"北宋","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"字太简。北宋宰相，光禄寺丞苏协之子。太平兴国五年（980年），考中状元，起家升州通判，迁左赞善大夫，入为右拾遗。太平兴国八年（983年），为知制诰，连续七年知贡举，坚持原则，公正无私，深得宋太宗的信任。雍熙三年（986年），充任翰林学士。淳化二年（991年），迁中书舍人，历知审官院、审刑院，迁给事中、参知政事。至道元年（995年），以礼部侍郎、知邓州，移知陈州。至道二年（996年），饮酒过度，去世，年仅三十九，追赠礼部尚书。","主要作品":"著有文集二十卷，不传，《文房四谱》。仅存《越江吟》词1首。"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":66.0,"姓名":"苏 耆","朝代":"北宋","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":67.0,"姓名":"苏舜元","朝代":"北宋","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"字叔才，后改字才翁，北宋大臣苏耆的长子，北宋诗人苏舜钦的兄弟，外祖父为新昌尉王旦。北宋大臣，文人。天圣八年（1030年），苏舜元被召试学士院，赐进士出身。历扶沟主簿，知咸平、眉山二县，通判延州。入为三司勾当公事，出提点福建路刑狱，移京西、河东、两浙，为京西转运使。以度支员外郎充三司度支判官。至和元年（1054年），苏舜元卒。","主要作品":"著有《奏御集》十卷、《塞垣近事》二卷、《奏议》三卷、文集十卷（蔡襄《墓志铭》，《郡斋读书志》卷一九著录《苏才翁集》一卷），均已佚。《全宋诗》卷二七二录其诗十二首，《全宋文》卷六三九收其文三篇。"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":68.0,"姓名":"苏舜钦","朝代":"北宋","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"字子美，出生于汴京（今河南省开封市）。北宋时期诗人、文学家。参知政事苏易简之孙。苏舜钦早年以父荫补太庙斋郎，调荥阳尉。景祐元年（1034年）进士及第，历知蒙城、长垣县。他在政治上倾向于以范仲淹为首的改革派。庆历三年（1043年），因范仲淹举荐，召试授集贤殿校理、监进奏院。庆历四年（1044年），以卖废纸钱办祀神酒会，被御史中丞王拱辰诬奏为“监守自盗”，罢官为民。庆历五年（1045年），南下苏州，筑沧浪亭自居。庆历八年（1048年），复官为湖州长史，未赴任即因病去世，时年四十一岁。","主要作品":"有《苏舜钦集》存世。苏舜钦才华出众，在宋初与与穆修一起倡导古文运动。其诗文质朴激切，是北宋诗文革新的重要作家，与欧阳修、梅尧臣交游，时称“欧苏”或“苏梅”。"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":69.0,"姓名":"杨子谟","朝代":"南宋","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":70.0,"姓名":"李崧霖","朝代":"清","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"字梦莲，四川中江人。嘉庆二十一年（一八一六）举人。工山水，不拘成法。初游江、淮间，归主眉山书院。","主要作品":"有三十六树梅花书屋诗钞。"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":71.0,"姓名":"熊梦吉","朝代":"清","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"嘉庆十三年（1808）举人。道光六年（1826）考选二等，授叙州府训导，二十七年（1847）卒于任所，年七十六岁。幼时其父尝语之曰：“人能吃亏，乃是佳兆。若逞机诈，好便宜，非保身治家之善术。”梦吉奉为格言，终身不忘。为人廉洁，任事无私，遇事善裁决。为学重根本，谆谆以教人。《中江县志》有传。","主要作品":"著有《管见琐言》、《春煦堂诗文稿》、《逸园文集》行世。"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":72.0,"姓名":"何盛斯","朝代":"清","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"字蓉生，中江人。道光戊子举人。","主要作品":"有《柳汁吟舫诗草》《游梓州琴良寺》。"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":73.0,"姓名":"李鸿裔","朝代":"清","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"字眉生，别号香严，晚号苏邻。四川中江人。近代诗人。倪豹岑、敖金甫称其诗：“才气飞动，造词浑雅，穿心镂肝，雅近李长吉，高华鸿朗，又似高青邱”。","主要作品":"著有《苏邻遗诗》二卷、《苏邻遗诗续集》一卷。\n李鸿裔的诗多题图及友人赠答之作，有《沪上杂诗》二十余首抒写对于上海崛起、中外杂处的感受。"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":74.0,"姓名":"王乃徵","朝代":"清","籍贯(原名)":"中江县","籍贯(现代)":"德阳中江县","经度":104.69,"纬度":31.04,"简介":"字聘三、平珊，光绪十六年进士，由庶常授编修，转御史，出知江西抚州府，以治行称最，旋擢京兆尹。后历任湖北、河南、贵州三省布政使。辛亥革命后隐居于沪，鬻文悬壶自给。","主要作品":"著有《嵩洛吟草》、《天目纪游草》等，已散佚。代表作《八声甘州 秋感，和归安宗伯，用屯田韵》《霜叶飞 金柅园即事，寄怀沤尹》"},"geometry":{"type":"Point","coordinates":[104.69,31.04]}},{"type":"Feature","properties":{"序号":75.0,"姓名":"李尤年","朝代":"汉","籍贯(原名)":"广汉县","籍贯(现代)":"德阳广汉市","经度":104.29,"纬度":30.98,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.29,30.98]}},{"type":"Feature","properties":{"序号":76.0,"姓名":"翟酺","朝代":"汉","籍贯(原名)":"广汉县","籍贯(现代)":"德阳广汉市","经度":104.29,"纬度":30.98,"简介":"字子超，广汉雒()人。好《老子》，尤善图纬、天文、历算。曾为舅报仇，流亡长安，以卜相、牧羊为业。安帝时拜尚书，上书指斥外戚威权过重，遭到外戚宠臣忌恨。后历官酒泉太守、京兆尹、将作大匠等。顺帝时被权贵诬陷下狱，获释后卒于家。","主要作品":"著有《援神》、《钩命解诂》十二篇。"},"geometry":{"type":"Point","coordinates":[104.29,30.98]}},{"type":"Feature","properties":{"序号":77.0,"姓名":"周满","朝代":"明","籍贯(原名)":"广汉县","籍贯(现代)":"德阳广汉市","经度":104.29,"纬度":30.98,"简介":"自幼聪颖好学。嘉靖年间进士。初授主事，累官至都御史。其治理滇南之海田，广西之弭□，宣大之阅军储，汀虔之督军务，皆有政绩。公余尝亲手抄书，五经、诸子及小说，皆细心精研。文尚富赡，时有豪宕之气。《汉州志》有传。","主要作品":"著有《周易象义》、《春秋原义》、《受庵文集》行世。"},"geometry":{"type":"Point","coordinates":[104.29,30.98]}},{"type":"Feature","properties":{"序号":78.0,"姓名":"张邦伸","朝代":"清","籍贯(原名)":"广汉县","籍贯(现代)":"德阳广汉市","经度":104.29,"纬度":30.98,"简介":"字石臣，号云谷，清乾隆二年（1737）生，乾隆二十四年（1757）己卯科举人，会试大挑一等，任辉县县令时，力治劣绅污吏，任光州州判时，赈济作到“无烂无遗”，了结积案3800余件，无一上诉。张氏任襄城知县时，按有车马者分轮次派差以均劳役，官民称善，《汉州志》记载张邦伸治绩为“政理民和，案牍清简”，以母疾告养，力辞归田，时年45岁，回归故里后，助修文庙，赈济族中穷人。卒于嘉庆八年（1803），终年67岁。","主要作品":"他好为诗，现仅存《云谷诗钞》八篇，著有《全蜀诗汇》《唐诗正音》《绳乡纪略》、《云栈纪程》《云谷文钞》《锦里新编》等共17部95卷，是广汉地区最多产作家之一。"},"geometry":{"type":"Point","coordinates":[104.29,30.98]}},{"type":"Feature","properties":{"序号":79.0,"姓名":"张怀溎","朝代":"清","籍贯(原名)":"广汉县","籍贯(现代)":"德阳广汉市","经度":104.29,"纬度":30.98,"简介":"生于清代乾嘉时期。其父张邦伸与李调元为同年进士，后李调元亲至张家贺其子中举，并携戏班连演三日以示庆贺。作为李调元诗学传人，其诗作风格继承并发扬了李调元的性灵说主张。《四家诗选》：张怀溎精选袁枚、王文治、赵翼、李调元四位诗人作品编成此集，首次提出“林下四老”的文人群体概念，展现乾隆时期诗坛风貌。","主要作品":"《磨兜坚馆诗钞》：个人诗集，收录其创作诗歌作品?。《后蜀杂事诗》：其中“护花帏幄一重重，煊染秋光分外浓。笑指此城真是锦，女墙十里种芙蓉”?[3]，生动记载成都自古遍植芙蓉的城市特色。"},"geometry":{"type":"Point","coordinates":[104.29,30.98]}},{"type":"Feature","properties":{"序号":80.0,"姓名":"张奇瑞","朝代":"清","籍贯(原名)":"广汉县","籍贯(现代)":"德阳广汉市","经度":104.29,"纬度":30.98,"简介":"岁贡生。博识洽闻，凡天文地理、医卜、风角诸书，靡不究极精微。康熙时，应乡试不第，遂绝意进取，以课徒著述为事。暇则布衫芒履，徜徉山水间，随意歌啸，借以自适。后卒于家。工诗，《四川通志》、《锦里新编》有传。","主要作品":"著有《鹤峰集》一卷行世。李调元谓其“诗沉着痛快，颇近少陵。《题涌泉》、《君平卜台》、《金雁桥》、《万人坟》数诗，皆力争上游，非宋元以下所能望其肩臂也。”"},"geometry":{"type":"Point","coordinates":[104.29,30.98]}},{"type":"Feature","properties":{"序号":81.0,"姓名":"张祥龄","朝代":"清","籍贯(原名)":"广汉县","籍贯(现代)":"德阳广汉市","经度":104.29,"纬度":30.98,"简介":"弱冠中拔贡。屡困乡闱，乃应四川布政使易佩绅之招入幕。光绪二十年（1894）进士。选翰林院庶吉士。散馆，授怀远县（今陕西横山县）知县。二十六年（1900）兼署长安县。后任大荔、南郑县知县。后辞官归田。清末病逝于家。工诗善词，所著《半箧秋词》，以与易实甫、况夔生、郑叔问诸名流唱和为多。宋育仁《半箧秋词跋》云：“子馥亦数称（朱）清真、（姜）白石，所为亦时得其真髓。”《广汉县志》有传。","主要作品":"先著有《前后蜀杂事诗》行世。自谓“作诗□逊吾妇，故遁而为词。”后著有《半箧秋词》一卷，《续半箧秋词》一卷，又与王鹏运、况周仪合著《珠玉词》一卷。叶公绰《全清词钞》、姜方锬《蜀词人评传》录有其词。"},"geometry":{"type":"Point","coordinates":[104.29,30.98]}},{"type":"Feature","properties":{"序号":82.0,"姓名":"秦 宓","朝代":"三国","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":83.0,"姓名":"符 载","朝代":"唐","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":84.0,"姓名":"杨 绘","朝代":"北宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":85.0,"姓名":"张 浚","朝代":"南宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":86.0,"姓名":"张 栻","朝代":"南宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":87.0,"姓名":"张枃","朝代":"南宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":"张浚次子，以父授承事郎，历广西经略司主管机宜文字、通判严州。时方年少，已有政声。召对，除知袁州，抑豪强，敛盗贼，以能见称。寻改知衢州。遇兄丧，请祠以营葬事，遂主管成都玉局观。后迁湖北提举常平，改浙西，督理荒政，兼摄苏、湖二州守。未几，迁两浙转运判官，升转运副使，改知临安府，奏减欠租四万缗，米八百斛。进直龙图阁，移知镇江。召还，除吏部侍郎。光宗绍熙元年（1190），转刑部侍郎。历知襄阳、建康、隆兴府，兼江西安抚使。减免重税，民困得苏。进端明殿学士，复知建康府。后以疾请祠，卒。《宋史》、《南宋书》有传。","主要作品":"善为文，《宋代蜀文辑存》录其文四篇。"},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":88.0,"姓名":"张忠恕","朝代":"南宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":"张浚孙，以祖入仕，调广西转运司主管文字，改通判沅州，主管京湖宣抚司机宜文字，知沣州。宋宁宗开禧三年（1207），入为籍田令。嘉定五年（1212），迁军器丞，进太府丞。历知湖州、司农丞、知宁国府。寻以言罢官。未几，起知鄂州，改湖北转运判官。召为屯田郎官。转户部郎官。入对，极言边事，其虑甚远。理宗即位，多所建言，为朝臣传诵 。忠恕后请外任，遂以直秘阁知赣州。旋受劾落职。绍定三年（1230），复官，提举冲佑观。旋卒。平生有闻张之教，明于义理之学。《宋史》、《南宋书》有传。","主要作品":"《宋代蜀文辑存》录其文一篇。"},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":89.0,"姓名":"何 耕","朝代":"南宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":90.0,"姓名":"李良臣","朝代":"北宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":"字尧俞,绵竹(今四川绵竹)人。李益谦、李流谦之父。徽宗政和五年(一一一五)上舍及第。高宗绍兴三年(一一三三)以左承议郎提点降赐库。绍兴七年(一一三七),以左朝奉郎除校书郎。绍兴八年(一一三八)春正月,以校书郎除工部员外郎;九月,以尚书礼部员外郎知简州。又曾知雅州、池州。事见《建炎以来系年要录》卷六六、一一一、一一八、一二二,《南宋馆阁录》卷七,《宋元学案补遗》卷四四、《四川通志》卷七上、《大清一统志》卷四〇三。","主要作品":"《全宋诗》原本所收残句:“士耻无名字,吾儿早振声。……勿贻麟楦笑,千古愧公卿。”增补修正为全诗:“士苦无名字,吾儿早振声。交游资直谅,议论斥纵横。一第真拈取,群经素讲明。勿贻麟楦诮,千古愧公卿。”\n《贺陈制置启》《太守与交代启》。"},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":91.0,"姓名":"李益谦","朝代":"南宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":"李良臣子，李流谦兄。","主要作品":"《行状》"},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":92.0,"姓名":"李流谦","朝代":"南宋","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":"约公元一一四七午前后在世]字无变，约宋高宗绍兴中前后在世。以文学知名。荫补将仕郎，授成都府灵泉县尉。秩满，调雅州教授。虞允文宣抚全蜀，置之幂下，多所赞画。寻以荐除诸王宫大小学教授。力乞补外改奉议郎，通判淹州府事。","主要作品":"著有《澹齐集》八十一卷，《国史经籍志》传于世。"},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":93.0,"姓名":"杨淮","朝代":"明","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":"万历元年癸酉国子监助教。（[清] 刘庆远 著《绵竹县志》卷三八）","主要作品":"《重修紫岩书院记》"},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":94.0,"姓名":"唐乐宇","朝代":"清","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":"清代诗人。字晓春，号九峰，别号鸳港。清乾隆三十一年授户部主事，升员外郎，官至南笼府太守。","主要作品":"精于九章算术，著有《东络山房诗文集》、《奇门纪要》等"},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":95.0,"姓名":"吴 照","朝代":"清","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":96.0,"姓名":"杨 锐","朝代":"清","籍贯(原名)":"绵竹县","籍贯(现代)":"德阳绵竹市","经度":104.23,"纬度":31.34,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.23,31.34]}},{"type":"Feature","properties":{"序号":97.0,"姓名":"范崇凯","朝代":"唐","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字金卿。善属文，开元中状元，明皇命作《花萼楼赋》，称为 天下第一。弟元凯，亦有文名。时号“梧冈双凤”。","主要作品":"《花萼楼赋》"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":98.0,"姓名":"王守约","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字原甫。景泰庚午举人。授湘乡县教谕。性方严有执，不苟 颦笑，常以忠信为主。肆力于诗，有唐人风调，邑宪副吴玉、陈令、 萧韶辈咸出其门，至老犹敬惮如及门时。善品士，历典关中、滇中 分试。致仕归，年九十三卒，","主要作品":"有《可庵集》"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":99.0,"姓名":"高世彦","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字仲修，号白坪，四川成都府内江县人。四川乡试第二名举人，嘉靖十一年（1532年）壬辰科第二甲第二十名进士。观户部政，授南京户部主事，改北刑部，升署员外郎，十五年十月因张延龄案被逮下狱，降判官，升沔阳州同知、荆州府同知，河南佥事，陕西参议，江西副使，浙江参政，河南按察使，右布政使，河南左布政使。","主要作品":"《贺少保赵大洲建华居》《冬江》《送李渠波二尹归柳州》"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":100.0,"姓名":"刘瑞","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字德符，按察佥事时敩子。颖异有大志，十岁能属文，父奇之， 语以圣贤性命之学，锐志向往。举弘治丙辰进士，改庶吉士，读中秘书，授检讨。壬戌，充同考试，简拔多海内名士，杨杲、何景明其著者。壬申，诏起副使，提学山西。丁母忧，服阕，补督学浙江。世宗即位，升南京光禄，疏均差、减耗、折羡、亲输四事， 从之。进南太常卿，寻升南礼部右侍郎。乙酉，视部事，疾作，端坐而逝。讣闻，给祭葬，赠礼部尚书。隆庆中，题谥“文肃”。","主要作品":"有《改本三国志》《敷纳稿》《幼学稿》《禁 垣奏草》《澧兰录》《征信录》《童观录》，杂序、记、碑、序、志、论、 议、赋、颂、铭、赞、启、古今体诗若干卷梓行。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":101.0,"姓名":"张玉林","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字邦辉。少醇谨介洁，笃志圣贤之学，诸生多从之游。马湖土官安鳌闻其名，延之师席，为置产筑室居之，固辞而返。登堂拜母，询甘旨，母语稍缓，即遣妻还母家，自是供养益不继。母泣下，林知之，亟遣人迎妻归，夫妇如初，母始悦。成化乙未举进士，观政刑部。寻除石首令，专 务德化，不任刑罚，士民翕然戴之。丁内艰，丧祭一仿古礼。起补 寿张县，九载秩满，升知北胜州，道卒。生平鲜伪行妄语，淘洗性灵，潜深理趣，孜孜以践履为实地， 以诚敬为主持，浮云富贵，糠秕词章。","主要作品":"所著《天地万物造化论》，抉奥阐幽，多所自得。有《静庵语录》藏于家。滇人宪副赵壁、关中 主事冯友端、汉川赵果、荣昌范聪、同里张作襄，皆门下士。乡人 采其行履，祀于学宫。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":102.0,"姓名":"李充嗣","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字士修。少与从弟如京，从西充马少宗伯学，初及门，适有边警，马举试策问充嗣，条对中肯，马深鉴赏。举成化丁未进士，选庶吉士，补户部主事，改刑部。辛巳，擢工部尚书，疏白茅港便民，三吴自是无水患。壬午嘉 靖改元，录平濠功，始晋太子少保。被召陈言，首以圣学正心、亲 贤远奸为急，条析蠹国、病民、强兵、病御戎数事，言词剀切，上嘉 纳焉。癸未改南兵部参赞，机务恩威并济，凡益国家便军民者，毅 然身任之。二品满，再考，诏进阶勋。世宗方倚重，遽乞骸骨，章七上，始允给驿归。至澧，省母墓，欲还不果，遂家焉，卒年八十七。遣官祭葬，赠太子太保，谥“康和”。","主要作品":"有《梧山集》《水利靖危奏议》 二稿行于世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":103.0,"姓名":"张潮","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"正德六年（1511）进士，入翰林院。嘉靖元年（1522）世宗嗣位，潮侍经筵，修《武宗实录》。未几，升侍读洗马学士。撰《诰日录国史》。世宗见潮讲论经史，敷说明畅，颇为赏识。二年（1523）主应天乡试。九年（1530）南郊建圆国邱，议者请全迁禁垣外。潮上疏谓坛距坦外尚远，故数以万计，倘无妨观瞻，宜仍其旧，以泽枯骨。议后终于罢迁。十年（1531）主会试。以母病乞侍养，不允。升吏部少宰。潮叹曰：“忘亲恋官，非孝也。”复上疏乞准归家侍亲。逾三月，母病卒，丁内忧居家。服除，越十五日，忽疾作，卒于官。《内江县志》有传。","主要作品":"著有《玉溪稿》行世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":104.0,"姓名":"马升阶","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字汝弼。举嘉靖戊子乡荐，应礼部试。闻王阳明讲学东南，毅 然向往，购其《语录》诵之，有当于心，遂决意性命之学。丁母萧 夫人忧，哀毁尽礼。谒选授武陵令，豪猾敛手，招贫民复业者三百 家。以直道忤上官，引归，士民刻像祠之。时伯兄进阶亦由襄阳解政归，父松山九十余，豆觞承养，乡里荣之。嗣遭父忧，筑庐山间， 绝迹城市。子鲁卿、孙鸣銮，俱以名进士登显宦，世其家。","主要作品":"所著有 《宜山集略》《百将传略》《慎思录》《易义会通》《经旨举要》《卜筮 考略》《随笔录》《五岳编》《武陵事迹》《马氏族谱》各一卷行世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":105.0,"姓名":"赵贞吉","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字孟静，号大洲。明嘉靖十四年（1535年）进士，隆庆时升宰辅；明代有名的政治家、理学家、教育家、文学家。他在玉溪注入的桂湖渠旁置建了玉溪庄，与赵贞吉齐名的蜀中12名诗人之一的高世彦（内江籍进士）《贺少保赵大洲建华居》诗云：“玉堂今赵相，桂月旧湖渠”，说的就是赵贞吉修建玉溪庄之事。赵贞吉在此授徒讲学，写下《与诸生会讲玉溪庄有作》一诗，此诗刻在玉带溪旁翔龙山资圣寺（宋建）的石碑上，经数百年雨打风蚀，字迹漶漫。","主要作品":"贞吉殁后，子鼎柱、景柱与门人龚侍御、邓刺史缀其遗稿为 《诗抄》《文抄》《讲义》数十卷，及《周南留著图》《年谱》行于世。\n有《赵文肃公文集》23卷存世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":106.0,"姓名":"赵蒙吉","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字仲通。自少卓荦不群，与兄文肃公自为师友，讲道励行，具 有经世大略。嘉靖辛卯登乡荐，屡上春官不第，督学姜宝荐于朝， 征授国子博士。寻以疾乞归，栖牛心山，澄心养性。临卒，与文肃 公谈原始反终之道，端坐而逝。","主要作品":"有《正学记》《上时宰乞归书》藏于家。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":107.0,"姓名":"何祥","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字子修。嘉靖甲午乡荐。少颖敏，与里中赵文肃、马宜泉友， 穷究经史，潜心理学。继事欧阳南野先生于成均，闻先立志、存耻 愤心之说，益觉真切有味。署遂平教谕，分考浙闱，得名士沈节甫辈，再署麻城，刘司马、耿中丞诸人雅重之。","主要作品":"所著有《洗心录》《性理要论》《诚仁解》 《家训》等卷，藏于家。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":108.0,"姓名":"刘望之","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字商霖。受业从伯文肃公，沉酣学问，举进士。授杭州府推官，摘伏发奸，蔚有声称。征为给事中，敢言极谏，时宰忌之。谪魏县丞，寻量移，历升浙江佥事，外艰，起补河南。","主要作品":"有诗曰：“丹心捧日如常在，赤手擎天奈老何。”其忠义类如此。\n有《一岩文集》《正韵便览》《魏县志》梓行。伯子翾、 仲子翲俱进士，历官有声，诸子及孙蝉联接武，世其家，事见《通志》。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":109.0,"姓名":"蒋如兰","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字伯善。从赵文肃游，长于天文历数。万历癸酉举于乡，丁丑 中乙榜。授衡阳谕，己卯分校顺天，得士崔邦亮、刘元霖等，皆一 时豪杰。壬午判云南，携二老仆，淡如也。丙戌守马龙，治简，学 益进。庚寅复守楚蕲，颇烦剧，政暇辄与士大夫讲学。壬辰，丁内 艰，哀毁成疾，端坐而卒。","主要作品":"所著有《闲居录》《楚中稿》。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":110.0,"姓名":"刘翾","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字元翰，望之子。嘉靖辛酉经魁，壬戌成进士。令渭南，多异 政，召入为御史，敢言极谏。巡长芦，条陈盐法，却羡十万两以充 公帑，按顺天，豪贵敛迹。上疏数十章，其大者如绝西山下四月八 日僧道淫度丑习，著为令。辛未会试，请广制额五十人，殿首张元 忭即在数中。时新郑相罣议，去途有观望意，飞章义责之，竟以是 结怨。后备兵浙江，以讨倭功受上赏，晋大参，与时相议左，嗾其 党劾之归。","主要作品":"有《西台疏草》若干卷藏于家。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":111.0,"姓名":"刘养直","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字敬夫。嘉靖戊午进士，授行人，升刑科给事中。数关策大计， 论张司马、毛中丞宜罢，声动朝宁。壬寅边警，畿辅戒严，议都城之外增筑罗城。会九庙更建，大司农告乏，世宗震怒，阅岁，人莫 敢言，养直独上封事，省费巨数十万。性恪愿持重，临事有执，居常不道人过。至谈天下事，则侃侃不倦，亦不务 炫赫以邀时誉。","主要作品":"有《漫兴诗集》《文集》数卷。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":112.0,"姓名":"马彦卿","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字次彰。蚤闻宜泉家学，长事张元与，晚得赵文肃印可，其学 主于静中有物。年三十二，举嘉靖戊午第五人。戊辰署金鸡学谕，立“崇正会”于朱陆书院，讲习经义，诸生多有成就。庚午分校滇试，荐拔得人，尹岐山曰：“先生以不得作近民之官为憾。”遂受事 报政，士民德之，后祀名宦。","主要作品":"尝订正《格物章》错简，学者称为“溪源先生”，著《寝寤编》数卷。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":113.0,"姓名":"阴武卿","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"少聪颖，七岁能文。十六岁游庠，冠诸生。嘉靖三十四年（1555）乡试第一，次年中进士。授南京主事。丁内忧居家。服除，起补刑部，晋正卿。推佥陕西学宪。任满，擢江西少参。寻改秩督广西学政。迁福建大参。以献策平民变及白莲教起义功，入为应天（今河南商丘市）尹。改太常卿。未几，擢保定副都御史。选将练卒，丈田粮，议赈，通河道，饬三关墩，励精图治，上赏之。自陈乞休。转留都大司马。武卿老成而有卓识，所在饬纪振肃。省冗费数万。会大饥，疏请先给两月军粮，以安卒伍。后忧劳成疾，卒于官。《内江县志》有传。","主要作品":"著有《月溪文集》。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":114.0,"姓名":"游缁","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字文达。幼负颖质，长受经，同里李洞山补郡庠，会刘五清侨 居锦官，因卒业焉。正德乙卯领乡荐，屡上春官不第。谒选守沔阳，奏蠲逋赋，给牛种，与民便利，厄于豪势，移邓州。丁外艰，起补易州，广军储，饬戎备，教诸生，政多可述。擢蜀府右长史，蜀故守礼国，成王最贤，赐坐问学，令为世子讲官。六年满，王特奏加升四 品服，丁内艰，服阕不起。徜徉山水间，会大工采运，役夫病者相 望，为给米药讫工罢，其济物爱人不倦若此。文尚六朝，诗喜声韵。","主要作品":"著有《在笥稿》《渔唱龙山堂漫稿》《文献录》。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":115.0,"姓名":"赵台柱","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"号海门，蒙吉子。隆庆庚午举孝廉，辛未一榜。事母刘孺人 以孝闻，膳省恪恭，不少离左右，以故三十年不就选。刘强之仕，方任楚岳州司李，清慎英敏，政声腾湘沔间，两台荐之于朝。为伯 大学士所仇沮，寻擢滇中尹，旬月致仕归。家居二十年，乡里称善 人长者，明农课子，不语及外事，按台奖云：“居乡高举，十年迹绝， 公庭出仕，冰操千载。”碑留户颂，数推乡饮大宾，寿七十终。","主要作品":"著有 《巊林集》《鸣皋集》数卷。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":116.0,"姓名":"杨所修","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"，字澹渊，又作谵渊，号云笠翁。明天启甲子科（1624年）举人。先后任过汝宁府上蔡县教谕、京曹郎署，累官至江南凤宿道（今安徽省凤阳县、宿州）（官五品），“人咸以‘杨观察’称之”。其画以雪竹、墨竹名世，为明代竹画的代表人物之一，与王绂、夏昶并称“雪竹三友”。","主要作品":"杨所修除能诗能书画外，还爱好嗜古抚琴，追风赏月，著有《鸿雪斋集》二卷（卷一为诗，卷二为书画）。可惜卷一不存，卷二也仅存两幅画作。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":117.0,"姓名":"马鸣銮","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字君御。幼从大父宜泉公口授经史，辄能成诵。赵文肃一见叹曰：“此国器也。”年十四补邑诸生，弱冠举于乡，登万历甲戌进 士。授水部主事，出榷杭关，羡金一毫不私。擢湖广佥事，晋少参，分辖五陵衡永，恩信大著。鸣銮伟干修髯，目光炯炯如神，料敌设奇，多出人意表。册封 一事，中外聚讼数年，卒如所议，叙录不及，公论惜之。","主要作品":"所著有《总 督奏议》《抚宣奏议》《郧中疏稿》《筹边赤牍》《平夏纪略》《冲点居 士养性篇》《凤麓山堂稿》藏于家。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":118.0,"姓名":"郑裕","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字有容。弘治壬戌进士。官行人，选户科右给事中，历礼、工、 吏三垣，诸所陈说，卓有名理，时少师杨石斋亟称之“识见明远”。谅运使陈述侵渔之枉，因星变上书，疏求勤圣学，恤人言，严用人， 重恩典，宽民力，饬边备。","主要作品":"有《奏议稿》《金陵集》《小莪眉集》藏于家。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":119.0,"姓名":"邓廷正","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字朝端。由监生，授两淮盐运司经历。性刚直不随，力佐运长 除豪猾，整饬鹾政，寻罢归。邑有不孝子，人莫敢发，廷正讼言殛 之，当途旌其直。戊子岁大歉，鬻产得谷百石，首倡输赈，赖全活 者甚众。世宗朝单骑诣阙，上治平十策：一顺民情，二亲民望，三 急民事，四御民战，五慎民牧，六重民命，七去民害，八清民税，九 服民情，十正民俗，咸关治理，报闻嘉纳。","主要作品":"生平好学，工诗文，所著 有《和唐诗鼓吹》《十段锦》《救荒议》。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":120.0,"姓名":"杨化元","朝代":"清","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"化元少敏悟，读书日记万言，为文下笔立就，尤善草隶。诗文书法，名噪一时。康熙四十一年（1702），与兄化贞同科举人。从弟化光次科也获隽，故时有前三杨（父桐、伯、叔楠于顺治十七年同科中举，人称三杨）、后三杨之誉。京试不第，教授生徒，多所成就。雍正二年（1724）谒选，授云南路南州知州。在任爱民重士，创建学宫，筑堤修堰，详减地丁，士民感德。擢刑部员外郎，旋升本部广东司郎中。在部四年，致仕归，卒于家。《四川通志》、《益州书画录》有传。","主要作品":"时人合辑其祖所修、父桐所为诗为《三杨诗集》。《内江县志》录有其诗。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":121.0,"姓名":"刘体仁","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"字同吾。性敏嗜书，为文高华粹美，力挽颓风。万历癸丑成进 士。以刑曹郎出知承天，清廉率属，养民课士，一以忠孝俭朴为本。铨部已议，擢楚宪，致仕归。不事干谒，邑人称“廉介先生”，卒年八十。子用怿，登崇祯癸酉贤书。","主要作品":"著有《怀归集》、《四书遵注正 解》、诗文若干卷，藏于家。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":122.0,"姓名":"冷时中","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"咸丰《内江县志》作“字心汾，号悔庵，内江人。有《雪椀集》。见《蜀雅》。又，字心芬，内江人。倜傥长于诗。国初从军，仕永历，官至监军道，见《宋荔裳文集》","主要作品":"有《雪椀集》。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":123.0,"姓名":"王慕吉","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"是明末进士，官至巡按和侍御，治湖堤有政绩；因蜀乱而走江浙，常与江苏丹阳诗词大家交游论诗。（吴伟业《监察御史王君慕吉墓志铭》）","主要作品":"有《槐园集》等著作数十卷，已佚"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":124.0,"姓名":"吴浩","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"幼好学，年十九中举人。督学咸宁（今湖北咸宁县），以造士为务，登科者众。寻请归。司徒杨鼎语人曰：“吾乡职教者，学行文章，自吴义生外，鲜能及者。”起补石泉（今北川县）令。奏请建孔庙，兴祭祀，倡教化，民感其德。秩满，擢云南曲靖府教授。再请归。寻病卒于家。《内江县志》有传。","主要作品":"著有《兰畹集》行世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":125.0,"姓名":"吴玉","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"成化二年（1466）进士。历官广西提学副使。性机警，博览典籍，稗官小说，无不涉猎。文甚富赡，时有浩荡之气。诗喜盛唐，或为集句，声律铿锵。晚年居家，与人谈古论今，历历如指掌。六旬之后，不饮酒服药。尝谓人曰：“吾自少壮至老，如行路然，信步所到耳。”尝修《内江县志》，邑人曰：“文献赖之存而不泯。”终年九十七岁。《内江县志》有传。","主要作品":"著有《昆斋诗集》行世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":126.0,"姓名":"萧如松","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"博学有大志。万历元年（1573）举人。荐任贵阳司务，以能，奉委勘播酋事。酋以千金为赂，如松正色却之，依法惩处。擢南京陕西道御史。巡视江防，整肃纪律。寻以丁外忧居家。服除，起补南京都察院，掌河南道事，巡视凤阳，兼摄京营十三道。后以父老归养。万历三十三年（1605）报命赴阙，晋光禄少卿。年馀复归，坚意终养。旋起补大理寺卿。未几告归。优游林下，以读书著述为乐。后病卒于家，年七十一岁。《内江县志》有传。","主要作品":"著有《建白稿》、《经制要略》、《洗冤要览》行世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":127.0,"姓名":"萧俨","朝代":"明","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"正统七年（1442）进士。历刑部郎中，平议南京囚犯，多所平反。累升河南参政。裕州（今河南方城县）守秦永昌不法，已置重刑。有诏逮按等官至京，唯俨抗辩不屈，得免。寻升贵州布政使。奏请颁乐器增解额，黔人甚感其德。后辞官归里。卒年七十八岁。《内江县志》有传。","主要作品":"著有《竹轩稿》三十卷、《明风雅广选》五十卷行世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":128.0,"姓名":"易含章","朝代":"清","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"嘉庆五年（1800）举人。十年（1805）进士。分发江苏任职，值淮郡水灾，奉委办赈，除侵冒诸弊，民困以□。继摄阳湖（今江苏常州市），旋丁父忧回籍。二十一年（1816）补江苏溧阳县知县。到任以诚感人，不事刑威，尝语人曰：“与其过忍，吾宁过宽”。然于违法者亦不少宥。含章又捐俸倡修育婴堂，士民相助成之。二十四年（1819）溧阳大旱，含章-缕陈溧民苦状，诏缓征额十分之三。溧阳旧有平陵书院，久旷废。含章集生童月课。捐千金为膏火费，公余辄进诸生讲课，往返不厌。每乡试买卷以赠。两充江南乡试同考官，所得皆知名士。道光元年（1821）补川沙（今上海市东部）同知。适奉调入闱阅卷，过劳成疾，遽卒。两江总督及诸佐僚吏俱有□联，溧士民走相哭奠。含章素嗜酒，尤嗜书。宦囊无他物，惟书四十簏，自署“留与子孙耕”云。《内江县志》有传。","主要作品":"著有《读易偶得》、《河图管见》、《卦图管见》、《太极图说》、《四书臆说》、《学庸方圆图》、《读史随笔》、《砚田琐悟》、《易氏家乘》、《易太令诗文集》行世。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":129.0,"姓名":"王果","朝代":"清","籍贯(原名)":"内江县","籍贯(现代)":"内江市","经度":105.06,"纬度":29.59,"简介":"乾隆甲寅（1794） 恩科举人，此后“流寓燕齐”，嘉庆壬戌（1802）成进士，嘉庆十七年（1812）任河南临漳县知县，嘉庆二十三年（1818）知山东 武定府，又署山东东昌府。","主要作品":"著有《临漳县志》《管窥录》《春鸣集》《盘峪山房存稿》《课孙草》《王氏世谱》等。"},"geometry":{"type":"Point","coordinates":[105.06,29.59]}},{"type":"Feature","properties":{"序号":130.0,"姓名":"李 石","朝代":"南宋","籍贯(原名)":"资县","籍贯(现代)":"内江资中县","经度":104.86,"纬度":29.77,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.86,29.77]}},{"type":"Feature","properties":{"序号":131.0,"姓名":"骆成骧","朝代":"清末明初","籍贯(原名)":"资县","籍贯(现代)":"内江资中县","经度":104.86,"纬度":29.77,"简介":"字公骕，清光绪二十一年（1895年）乙未科状元，是清朝唯一一位四川籍状元，被称作“布衣状元”。曾祖父是骆朝珩，祖父是骆恩升，父亲是骆腾焕。\n骆成骧9岁就读锦江书院，14岁州试第一名，调尊经书院深造。光绪二十四年（1898年）任京师大学堂提调，支持维新变法。光绪三十二年（1906年），奉清廷之命，赴日本法政大学留学，考察宪政。他曾主政四川高等学堂（今四川大学），对当时的高等教育贡献卓著。","主要作品":"留有诗文集《清漪楼遗稿》五卷，收诗902首，文29篇。"},"geometry":{"type":"Point","coordinates":[104.86,29.77]}},{"type":"Feature","properties":{"序号":132.0,"姓名":"韩驹","朝代":"北宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"字子苍，仙井监人。少有文称。政和初，以献颂补，假将仕郎，召试舍人院，赐进士出身，除秘书省正字，寻坐为苏氏学，谪监华州蒲城县市易务，知洪州分宁县，召为著作郎，校正御前文籍。宣和五年，除秘书少监。六年，迁中书舍人，兼修国史。绍兴五年，卒于抚州，进一官致仕，赠中奉大夫，与遗泽三人。","主要作品":"《仙泉虞童子郎使者闻诸朝三年不加考故作二绝以赠之归》"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":132.0,"姓名":"韩驹","朝代":"北宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"字子苍，号牟阳，学者称他陵阳先生。陵阳仙井（今四川井研）人。尝在许下从苏辙学。徽宗政和初，因献颂得官，召试舍人院，赐进士出身,任秘书省正字。当时正值禁止元□党人之学,不久即因学苏辙而被贬官监华州（今陕西华县）蒲城县市易务。后知洪州分宁（今江西修水）县，又召为著作郎。宣和五年(1123)被任命为秘书少监，次年升中书舍人兼修国史。高宗绍兴元年(1131)，知江州（今江西九江）。绍兴五年，在抚州去世。","主要作品":"著有《陵阳先生诗》4卷,有宣统庚戌(1910)姚埭沈氏《江西诗派韩饶二集》本。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":133.0,"姓名":"陈祐","朝代":"北宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"字纯益，仙井人。登进士。元符末，以吏部员外郎拜右正言，上疏乞除党禁，迁右司谏。又论林希过则归君，慢上不敬。希坐降知舒州。又论章惇、蔡京、蔡卞、郝随、邓洵武忤旨，通判滁州。后卞乞贬党籍，伯雨等，祐在数中，编管沣州，徙归州承议郎。卒。虽遭迁逐，而直声益著。","主要作品":"著《陈司谏集》二卷。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":134.0,"姓名":"喻汝砺","朝代":"南宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"仙井监人，有气节，工诗文。靖康进士，知阆中县。时青苖法行，提举司欲还钱取粟，会支军粮，乃以共钱籴军粮易钞，而市竟不扰。事见保宁府名宦志。升转运使。建炎初，为祠部员外郎，不附割三镇之议。闻金立张邦昌，扪其膝曰：此膝安可屈哉！遂号扪膝先生。归隐于印山之阳。诗文崄怪挺绝，简州刘光祖为序。","主要作品":"有《草堂集》十四卷。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":135.0,"姓名":"李舜臣","朝代":"南宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"南宋隆州井研人，字子思。史学家李心传之父。八岁能属文。少长通古今，推迹兴废，洞见根本，慨然有志于天下。中乾道二年进士第。教授成都府。干办诸司审计司，迁宗正寺主簿，重修《裕陵玉牒》。","主要作品":"所著书《群经义》八卷、《书小传》四卷、《文集》三十卷、《家塾编次论语》五卷、《镂玉余功录》二卷。子心传、道传、性传。以性传官二府，赠太师、追封崇国公。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":136.0,"姓名":"李心传","朝代":"南宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"字微之，亦字伯微，号秀岩，隆州井研人，南宋孝宗乾道二年（1166年）生。庆元元年（1195年），曾参加乡试，未能上榜，于是从此不再参加科举考试，而是安心闭门著书。","主要作品":"所著成书，有《高宗系年录》二百卷、《学易编》五卷、《诵诗训》五卷、《春秋考》十三卷、《礼辨》二十三卷、《读史考》十二卷、《旧闻证误》十五卷、《朝野杂记》四十卷、《道命录》五卷、《西陲泰定录》九十卷、《辨南迁录》一卷、诗文一百卷。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":137.0,"姓名":"牟 巘","朝代":"南宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":138.0,"姓名":"牟子才","朝代":"南宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"字存叟，号存斋，井研人。牟桂子，宋代官吏、学者。宁宗嘉定十六年（1223）进士，调洪雅尉，监成都府榷茶司卖引所。理宗宝祐元年（1253），以军器少监兼国史院编修官、实录院检讨官、崇政殿说书，累迁礼部尚书兼给事中。度宗即位，进端明殿学士。以资政殴学士致仕。其孙牟应龙亦为学者，人称祖孙三才人。","主要作品":"有《存斋集》，已佚。现存作品《风瀑竹·阁住杏花雨》"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":139.0,"姓名":"牟郧","朝代":"南宋","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"牟子才子，亦为学者。","主要作品":"著有《陵阳集》，"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":140.0,"姓名":"胡世安","朝代":"清","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"字处静，别号菊潭，四川资州井研县（今四川省乐山市井研县）人。明崇祯元年（1628）进士，曾任礼部尚书、武英殿大学士兼兵部尚书、太子太保、少傅兼太子太傅、秘书院大学士、少师兼太子太师。胡世安工诗文。","主要作品":"著有《秀岩集》十一卷，凡诗二十二卷，文九卷，及《大易则通》、《禊帖综闻》、《异鱼图赞笺》、《异鱼图赞补》。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":141.0,"姓名":"胡元善","朝代":"清","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"字葆初，家贫，厉精于学。一门自相师友，怡怡如也。乾隆四十二年，以选拔贡生，朝考二等，就职教论。四十四年举于乡。旋借补江安训导，擢成都教授。久之，以知县截取，发云南试用，寻署赵州知州。元善清廉慈惠，舆论翕然。莅事才期月，遽呈乞归。","主要作品":"《葆初文肪》二卷，《江上四楼记》《修建文昌祠及庄严神象记》"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":142.0,"姓名":"胡谐善","朝代":"清","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"字孔皆，元善季弟。少聪慧，有神童之誉。诗文脍炙人口，颇众此本，其卒后，拾遗而成者，非足本也。","主要作品":"《孔皆遗文》二卷"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":143.0,"姓名":"张崇元","朝代":"清","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"选嘉庆十八年（1813）拔贡生，授江安教谕。课士以诚，士林称颂。秩满，以知县发安徽试用。道光二十五年（1845）补天长县（今属安徽省）知县，勤政爱民，有惠政。逾年移任贵池，天长士民诣院司乞留。二十八年（1848）卒于官，年六十五岁。《井研县志》有传。","主要作品":"著有《调笙集》四卷、《听钟馆诗集》行世。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":144.0,"姓名":"曾志春","朝代":"明末清初","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"力学能文。事父母至孝。道光五年（1825）拔贡。知县陈垲闻其贤，聘主来凤书院讲席，县有新政，辄与志春共商。志春待弟子以诚，循循善诱，听者忘倦，先后成就至数百人。《井研县志》、《益州书画录》有传。","主要作品":"著有《雩亭遗稿》二卷。又善楷书，气格近颜真卿，时人重之。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":145.0,"姓名":"吴锡昌","朝代":"明末清初","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":"少强记。年十二应州试。每纳卷出，与诸童待庑下，附掌论史，或难以十六国杂事，锡昌条举无差爽。及为诸生，益究心古训。同治十三年（1874）张之洞督蜀时，治经已著声名。后博考海外辞书，为《五洲沿革表》、《大事记》二书，未竟而卒，年四十六岁。《井研县志》有传。","主要作品":"著有《十三经源流图说》二卷、《尧典月令中星考》二卷、《五代州军表》一卷、《广益斋集》五卷行世。"},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":146.0,"姓名":"廖 平","朝代":"清","籍贯(原名)":"井研县","籍贯(现代)":"乐山井研县","经度":104.08,"纬度":29.66,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.08,29.66]}},{"type":"Feature","properties":{"序号":147.0,"姓名":"樊星炜","朝代":"清","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾翠屏区","经度":104.63,"纬度":28.77,"简介":"字紫景，明季选贡，尝受业于樊我劬、尹子求。少有德器，乡先达咸呼为樊景星。流贼入蜀，团练乡勇，以保乡族。国初，屏迹山林。太守张利宾敦请不就，颜其居曰先辈典型。","主要作品":"著《介景堂集》、《随笔》二十卷，未刻。"},"geometry":{"type":"Point","coordinates":[104.63,28.77]}},{"type":"Feature","properties":{"序号":148.0,"姓名":"樊曙","朝代":"清","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾翠屏区","经度":104.63,"纬度":28.77,"简介":"，字旭东，宜宾人。明末以门荫袭指挥佥事。博通典籍。寇乱后，家业萧然，躬耕养母。弟?流寓滇中，老艰嗣息，遣人迎归，为之置妾，生一子。吴逆迫以伪命，力拒之。年七十二，卒。著有《楚泽吟诸刻》。”","主要作品":"著《五石斋稿》二卷，《楚泽吟诸刻》。"},"geometry":{"type":"Point","coordinates":[104.63,28.77]}},{"type":"Feature","properties":{"序号":149.0,"姓名":"杨端","朝代":"清","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾翠屏区","经度":104.63,"纬度":28.77,"简介":"字正夫，号立庵。雍正拔贡，任成都县教谕。学问渊博，著述甚富。嘉靖壬申编纂通志。其孙出所辑县志稿十三卷，断自戊子以前，攺正讹谬，多可采录。","主要作品":"所著已刻者《剑州志》、《存古录》，未刻者《成华合志》、《集古录》、《清白堂诗稿》。"},"geometry":{"type":"Point","coordinates":[104.63,28.77]}},{"type":"Feature","properties":{"序号":150.0,"姓名":"赵树吉","朝代":"清","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾翠屏区","经度":104.63,"纬度":28.77,"简介":"字沅青(一作元卿），道光庚成(1850年）进士，钦点翰林院庶吉士，癸丑(1853年）授翰林院编修，担任国史馆总纂，壬戌(1862年）会试同考官。外放掌江西道监察御史，内调和科绘事中，工科掌印给事中，任台谏八年，曾多次上 书弹刻权贵，声震朝野。旋出为云南迄西兵备道，来赴任，以许当路，引疾归。工书画。","主要作品":"著有《郁郁山房文集》四卷、《疏草》二卷，《瓮天琐录》一卷。"},"geometry":{"type":"Point","coordinates":[104.63,28.77]}},{"type":"Feature","properties":{"序号":151.0,"姓名":"赵清熙","朝代":"清","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾翠屏区","经度":104.63,"纬度":28.77,"简介":"字秋潭，又名尔澄。出身书香门第。年少应清廷县试、府试均名列前茅，后补山东某县县丞。清光绪二十四年(1898年）实行变法维新，赵在山东响应。变法失败后，赵清熙愤懑返宜，开堂讲学，以求储才兴国。后被推任叙州团练学堂、武备学堂、宜宾商业学堂、叙庆蚕业学堂等校监督以及宜宾县教育会长、教育团长、自治研究所所长等职。宣统三年(1911年），赵清熙不顾地方封建势力的反对，与李正伦坚持创办宜宾女子简易师范学堂于学盛街，并自任堂长。民国10年(1921年）暑期返乡劳作，锄地时不慎伤了脚，患破伤风不治而逝。","主要作品":"赵清熙著有《商务方针》、《秋潭诗文联稿》等，惜未刊行，今已散佚无存。"},"geometry":{"type":"Point","coordinates":[104.63,28.77]}},{"type":"Feature","properties":{"序号":152.0,"姓名":"牟志夔","朝代":"明","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾南溪区","经度":104.98,"纬度":28.85,"简介":"明朝万历三十二年(1604）进士，做过山西巡抚、都察院都御史等官。牟志夔曾经是大宦官魏忠贤的党羽，故意扣压诏令拖延时间，致使东林党人、政治家-星晚年含冤而死。","主要作品":"曾经为南溪城西的桂溪桥撰写了《桂溪桥碑记》。"},"geometry":{"type":"Point","coordinates":[104.98,28.85]}},{"type":"Feature","properties":{"序号":153.0,"姓名":"包汝谐","朝代":"清末民初","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾南溪区","经度":104.98,"纬度":28.85,"简介":"字弼臣，宜宾南溪人，1831年（道光十一年）出生于书香世家。包家到他这一代时，家道败落，十分凄苦。逆境中的包弼臣发奋读书，1851年（咸丰元年）20岁时考上廪膳生，并以辞赋闻名于郡县。1852年（咸丰二年），时任四川学政的何绍基按试叙州（宜宾）时，对包弼臣大加赞赏，称他和同里的罗肃、宜宾的赵树吉为“叙州三杰”。1860年（咸丰十年），包弼臣叔父包欣芳病逝北京，包随叔父灵柩回到南溪。1867年（同治六年），36岁的包弼臣中举。主考官就是过去在京时很赏识他的孙毓文。1868年（同治七年），包弼臣赴京参加会试不中，回乡主讲本邑“龙腾书院”。1875年（光绪元年）44岁时，任盐源训导。从1875年任盐源训导到1883年第四次赴京会试这8年，是魏碑“包体”形成阶段，也是他一生中创作书画、诗文的鼎盛时期。\n民国六年（1917年）7月14日，包弼臣突发脑溢血去世，终年86岁。","主要作品":"著有《南土遗吟录》《谷叟诗文稿》《西园记》《读书日记》等。宜宾博物院藏有包行书横披《超然赋》。"},"geometry":{"type":"Point","coordinates":[104.98,28.85]}},{"type":"Feature","properties":{"序号":154.0,"姓名":"罗维静","朝代":"清","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾南溪区","经度":104.98,"纬度":28.85,"简介":"字似山乙酉拔贡生少颖异读书过目不忘性简默寡言沉思独往每有所得辄蒙被兀坐数日不出及发而为诗悲歌慷慨枨触无端外而风俗人心内而性情骨肉无不各寓乎其中乾隆间诗人尤服膺藏园又尝欲裒蜀中诗人蔡雪南李药庵以下诗为一集惜未成而卒年三十二士林悼之","主要作品":"著有《百药山房诗集》行于世，《南溪乐府》采入艺文志。"},"geometry":{"type":"Point","coordinates":[104.98,28.85]}},{"type":"Feature","properties":{"序号":155.0,"姓名":"杨卓","朝代":"清","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾江安县","经度":105.07,"纬度":28.73,"简介":"乾隆三十年（1765）举人。三十四年（1769）进士，授江苏青浦县知县。□任后，衡文课士，终日不辍。惠政颇多。曾与王昶合纂《青浦县志》。平生不善书，亦不喜书，然友人诗文，得之辄亲手抄录。解官归里后，掌教东川、雁江、鹤山书院。从学者数百人，造就颇多。后卒于家。性豪迈，喜交游，座上客常满，有孔北海风。善诗古文词。《四川通志》有传。","主要作品":"著有《鹪鹩集》《望海吟》《渔亭丛话》行世。孙桐生《国朝全蜀诗钞》录有其诗。"},"geometry":{"type":"Point","coordinates":[105.07,28.73]}},{"type":"Feature","properties":{"序号":156.0,"姓名":"傅增湘","朝代":"清末民初","籍贯(原名)":"宜宾县","籍贯(现代)":"宜宾江安县","经度":105.07,"纬度":28.73,"简介":"字叔和，号沅叔，别署双鉴楼主人、藏园居士等，四川江安人。光绪二十四年（1898）戊戌科进士，翰林院庶吉士。1902年入袁世凯幕府。","主要作品":"著有《藏园瞥目》《藏园东游别录》《双鉴楼杂咏》等。"},"geometry":{"type":"Point","coordinates":[105.07,28.73]}},{"type":"Feature","properties":{"序号":157.0,"姓名":"孙光宪","朝代":"五代","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"字孟文，自号“葆光子”，陵州贵平（今四川省仁寿县）人。五代时期荆南大臣、文学家。孙光宪词以情景交融、婉约缠绵见长。如《清平乐》写一青春少女因为“连理分枝鸾失伴”而产生的春恨愁思，“掩镜无语眉低，思随芳草凄凄”，写得极其哀婉，令人同情。","主要作品":"代表作有《浣溪沙》《菩萨蛮》《虞美人》《酒泉子》《清平乐》《更漏子?》《上行杯》《南歌子》《应天长》等。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":158.0,"姓名":"何 郯","朝代":"北宋","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":159.0,"姓名":"龙昌期","朝代":"北宋","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"著书百余卷，嘉祐四年（1059）诏取其书，时年八十余，诣京师，赐五品服，以欧阳修等反对，追夺所赐遣归，卒（《续资治通鉴长编》卷一九○）。事见《宋史》卷二九九《胡则传》。","主要作品":"有《竹轩小集》、《龙昌期集》，不传。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":160.0,"姓名":"李 新","朝代":"北宋","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":161.0,"姓名":"韩 驹","朝代":"北宋","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":162.0,"姓名":"何 栗","朝代":"北宋","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":163.0,"姓名":"贠兴宗","朝代":"南宋","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"字显道，著名宋朝大臣、学者。间约公元1174年前后宋孝宗淳熙年初前后在世。未及第时，贠兴宗读书九华山，因号九华。荐除教授。召试，擢著作郎，国史馆编修，实录院检讨。宋乾道中年，贠兴宗曾上疏劾贵幸，卒中谗去职。侨居润州以终。","主要作品":"著有《九华集》五十卷，《国史经籍志》又有辩言及采石战胜录，并传于世。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":164.0,"姓名":"虞允文","朝代":"南宋","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"字彬父，一作彬甫。南宋初期名臣，唐朝名臣虞世南之后。宋高宗绍兴二十四年（1154年），虞允文登进士第。累官中书舍人、直学士院。绍兴三十一年（1161年），以参谋军事犒师于采石，指挥三军大破南侵的金帝完颜亮，使“宋事转危为安”。次年，任川陕宣谕使，与大将吴璘共谋进取，收复陕西数处州郡。乾道元年（1165年），拜参知政事兼知枢密院事。乾道三年（1167年），出任四川宣抚使、知枢密院事。乾道五年（1169年）拜相，任用胡铨、王十朋等。乾道八年（1172年），加授左丞相兼枢密使、特进，旋即再镇四川，封爵雍国公，世称“虞雍公”。淳熙元年（1174年），虞允文去世，年六十五。累赠为太师，谥号“忠肃”。","主要作品":"有《虞雍公奏议》等传世，今多已亡佚。《宋诗纪要》及《宋代蜀文辑存》辑录其作品。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":165.0,"姓名":"虞刚简","朝代":"南宋","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"字仲易，一字子韶，人称沧江先生，虞允文之孙。乾道九年（1173年），以郊恩授承奉郎，再举礼部，淳熙十五年，监郫县犀浦镇酒税。历任华阳丞、成都府路都钤辖司干办公事、通判绵州等职。虞刚简又召赴都堂审察，寻主管武夷山冲佑观。后起知渠州，改黎州、果州、万州，皆为御史弹劾罢官，虞刚简闲居七年。嘉定十一年（1218年），起知简州。嘉定十五年，虞刚简擢夔州路提点刑狱，改利州路。宝庆元年（1225年），虞刚简奉祠归乡。于宝庆三年（1227年）卒，年六十四岁。","主要作品":"著有《语解》《诗说》等，不传。《全宋》第四册 录其词一首。《全宋诗》卷二七八七录其诗四首。其文收入《全宋文》卷七七三。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":166.0,"姓名":"虞 集","朝代":"元","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":168.0,"姓名":"吴 当","朝代":"元","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":169.0,"姓名":"雷畅","朝代":"清","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"字燮和，号快亭。雍正七年（1729），选为拔贡生。历任平遥知县、沁州知府、常德知府、长沙知府、汉中道、山西济南东道、浙江粮储道及湖北、山东、山西按察使。乾隆三十四年（1769）冬，补授内阁侍读学士。后因足疾发作，乞退，获准回井研终养。乾隆四十二年（1777）卒于井研千佛老家。雷畅从27岁起，在外为官达40余年，死后墓志铭曰：“孝笃于亲，忠全于臣，律身维严，当官以诚。”","主要作品":"有《雷阁学集》10卷传世。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":170.0,"姓名":"雷翀霄","朝代":"清","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"字雷峰，号千佛山樵，晚号五林叟，畅之子。乾隆庚辰举顺天乡试，丙戌成进士，选入庶常，散馆授翰林院编修，以父致仕，侍养归乡。父殁，丧葬如礼。狄生而颖异，随父任齐、晋、楚、浙间，见益阔，师友日益众。为词章，渊博无涯涘。五七言作，酷肖香山、东坡，随意吐露，成一家言。工作字，引笔行墨，若惊鸿，若游龙，苏、黄、米、蔡兼擅其长。以此沉酣恣肆于藻翰中，不乐仕进。性磊落好施，恤亲族之贫，济友朋之急。年六十有五，卒于家。","主要作品":"所著《二则轩全集》行世。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":171.0,"姓名":"雷腾霄","朝代":"清","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"字行斋，号双峰，宣化知府时之子，出继季父雷昂。性颖悟，力学不倦，笃于孝友。乾隆壬午举于乡，挑发直隶，历署深泽、长垣知县。畿辅要冲，差使纷繁，所至有政声。公余即以制义指授多士。未几病归，卒于家。两署县事，在官祗数月，治绩未尽所长，而经术湛深，文行高卓。以侄轮官，覃恩貤赠朝议大夫。","主要作品":"所著有《竞爽轩文集》行世。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":172.0,"姓名":"游文璇","朝代":"清","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"乾隆二十一年（1756）举人。精制举业，以先正为宗。为学沈思解悟，每与门人讲论，明朗畅达，人人意有所得。晚年崇尚理学，于濂洛关闽之书，俱能析其奥。性坦率，待人从无疾言遽色。仁寿令俞公慕其文行，延主鳌峰书院十余年。及门之士入县学登贤书者三百余人。五十四年（1789）授邻水县教谕。五十九年（1794）解组归。卒于家。门人为立德教坊，永宁知县朱云焕撰赞文。《四川通志》有传。","主要作品":"著有《逸斋存草》行世。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":173.0,"姓名":"杨应达","朝代":"清","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"字觉斋，恩贡生。家故贫，胸次洒落，得饩金便购古书满架，四壁萧然，而歌啸声不辍。馆归，有修脯费余，戚里争贷。门生某逋负二三百金，不之索，以为才也。一眠一饭、一行，俱教儿辈诵书，日有吟诗。（《仁寿县志》）","主要作品":"著《柘园诗草》数卷。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":174.0,"姓名":"夏简","朝代":"清","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"号蕴山，博古耽吟，有唐音。授徒贵平、净林、龙江三寺二十余年，绿水红崖之胜，古迹禅宗之遗，益增感发。咸丰巳未卒。","主要作品":"著有《绿川诗集》、《东山诗集》。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":175.0,"姓名":"陈韶翕","朝代":"清","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"号韵翁，贡生。父言，母氏杨善病，侍奉汤药，无少离。与韶舞、韶南、韶湘筑草堂金龟山下，日吟诗。王藕船曰：文章性情，兄弟师友。卒年五十岁。","主要作品":"著有《韵翁诗草》。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":176.0,"姓名":"金伯纶","朝代":"清","籍贯(原名)":"仁寿县","籍贯(现代)":"眉山仁寿县","经度":104.14,"纬度":30.0,"简介":"号凤冈，监生，豪宕耽文酒，笃于友谊，与吴省三、杨应达诸人相唱和，甚疏财，家以故窘。卒年五十岁。","主要作品":"著有《凤冈诗草》、《人物志》。"},"geometry":{"type":"Point","coordinates":[104.14,30.0]}},{"type":"Feature","properties":{"序号":177.0,"姓名":"苌 弘","朝代":"东周","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":178.0,"姓名":"王褒","朝代":"西汉","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"字子渊，文学家，生卒年不详。蜀资中（今四川省资阳市 墨池坝）人。元和志：褒，资中人。班固前汉书本传：蜀人也。其生卒年失载，只知他文学创作活动主要在汉宣帝（公元前73～前49年在位）时期。","主要作品":"他是我国历史上著名的辞赋家，写有《洞箫赋》等赋十六篇，与扬雄并称“渊云”。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":179.0,"姓名":"赵 逵","朝代":"南宋","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":null,"主要作品":null},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":180.0,"姓名":"张方","朝代":"南宋","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"宋宁宗庆元五年（1199）进士。除普州教授。召对，指陈激切，无所避忌。擢国子监丞，转太常博士。后历知嘉定府、果州、邛州、眉州。提点夔州、利州、成都各路刑狱公事，兼四川制置司参议。尝于汉中修复小河堰，减除民钱三十万缗，米二千余斛。未几，诏进刑部郎官、直秘阁，不赴。乃奉母还乡，建学舍，筑圃屋，集同里之秀士，日与讲习，以此终老。为人廉明刚介，见义必为。尝作《心箴》以自警，且刻铭座右云：“敬安肆危，勤逸怠劳。”《宋史翼》、《四川通志》有传。","主要作品":"著有《夏时至别录》一卷、《夏时考异》一卷、《李峤一百二十咏注》、《亨泉遗稿》一百卷，均佚。《宋诗纪事补遗》、《补续全蜀艺文志》等六书录其诗六首，《宋代蜀文辑存》录其文二篇。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":181.0,"姓名":"张山翁","朝代":"南宋","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"宋理宗景定三年（1262）进士。恭帝德元年（1275），除荆湖宣抚司办公事。元兵临鄂，鄂守张晏然议纳款降元，山翁以书怒斥之。晏然既降，山翁被执军前，元人诱以高官，终不屈。元人义之，免杀。帝祥兴二年（1279），宋亡。山翁守志不仕，遂退居黄鹤山，聚徒教授。后卒于家。《宋史》、《南宋书》有传。","主要作品":"著有《南纪集》、《缁林集》、《藏云山集》、《相锄集》，均佚。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":182.0,"姓名":"张元电","朝代":"南宋","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"正德三年（1508）进士。初为御史，弹劾无所避，忤权宦刘瑾，改刑部主事。迁保定知府，以未给权奸江彬纳贿，被诬系狱。出狱后，改知浙江处州。黄岩有聚众劫掠者，元电晓以祸福，即遁去。后免官家居。《四川通志》有传。","主要作品":"著有《石峰书法》、《张元电文集》。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":183.0,"姓名":"王维兰","朝代":"清","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"维兰字香谷，集中皆计偕北上口占诸作，姜工部先为之序，继张礼源复序，称其沉郁顿挫真逼三唐，甫年三十，遽遭不测，为可惜也。《资阳县志》有传。","主要作品":"《醉芳斋诗集》"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":184.0,"姓名":"张象","朝代":"清","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"康熙三年（1664）进士。授河北饶阳县令，有治声。擢山东胶州知州，设养生堂，葺药室，抚婴疗病，全活甚众，民皆感德。擢都水司，转兵部职方主事，致仕归。后卒于家。象文思敏捷，下笔为文立就。“诗亦根柢至性，粹然不疵。”（《蜀雅》卷十一）。与其兄象枢、从弟象华俱以诗名，时称“安岳三张”。《四川通志》、《锦里新编》有传。","主要作品":"著有《处和诗集》行世。张邦伸《全蜀诗汇》、李调元《蜀雅》、孙桐生《国朝全蜀诗钞》录有其诗。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":185.0,"姓名":"周于仁","朝代":"清","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"康熙四十七年（1708）举人。以振兴学校为先务，请于邑令郑吉士，募建凤山书院于城南。应邀纂修《安岳县志》，搜罗采访，皆一人所为。雍正初任福建永春县知县。捐修梯云、扶雅、同文三馆以造士，文风大变。听讼无冤民，每审一案，民树一旗以志德，及调将乐，旗将盈百，撤所竖旗杆建迎晖门外溪桥，民称为“平政桥”。十一年（1733）升任台湾澎湖通判。严惩戌兵扰民，民得以安。秩满任协办。乾隆元年（1736）因病致仕。《潼川府志》、《安岳县志》有传。","主要作品":"撰写《澎湖志略》，为台湾澎湖早期珍贵文献。另著有《海屿志》、《安岳县志》、《慕游集》行世。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":186.0,"姓名":"邹楠","朝代":"清","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"乾隆十八年（1753）拔贡。三十五年（1770）举人。嘉庆五年（1800）春白莲教入境，县令延楠筹团练，筑天马砦。后又议置学田，士民感之。为学务纯，精《易》理，崇理学，于《周子图说》独得心解，经史外凡诸子百家，靡不究览。后卒于家，年八十九岁。学者称紫峰先生。《潼川府志》、《益州书画录》有传。","主要作品":"著有《学庸辑解》、《读史辑要》、《策略》、《紫峰笔谈》、《书法律梁》行世。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":187.0,"姓名":"邹绍观","朝代":"清","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"嘉庆九年（1804）乡试解元，联捷进士。签分广东，历翁源、文昌、饶平、琼山、乐会（今琼海县）、顺德等县知县，所至俱擒巨滑，弥盗贼，功德及民。后以亲老告归。卒于家，年七十五岁。《潼川府志》有传。","主要作品":"著有《天文图》、《古今堪舆形势略》、《西征日记》、《声音韵字谱》、《人身经脉图》、《慎惧余篇》行世。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":188.0,"姓名":"王东园","朝代":"清","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"乾隆四十八年（1783）举人。选元城县（今河北大名县）知县。界连齐豫，民俗强悍，讼狱繁滋。应?明敏，折狱如神。平日案无留牍。尝躬入乡村劝农，遇有讼呈讼者，就地树荫下讯解，喻以利害，晓以大义，劝其息讼。士民爱戴如父母。匾其堂曰：“沙麓风清”。又捐俸设□□仓、筑红花堤。嘉庆二十五年（1820）改调永年县知县，寻告归。年七十九岁卒于家。《潼川府志》有传。","主要作品":"著有《石华经说》、《东园诗集》、《东园文集》行世。"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":189.0,"姓名":"周文言","朝代":"清","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"文言字易简，资阳人，乾隆丙子举人，任龙安保宁教授，推升广东临高县知县，迁儋州知州，谢病归，卒于家。","主要作品":"著《云水集》"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":190.0,"姓名":"毛文昭","朝代":"清","籍贯(原名)":"资阳县","籍贯(现代)":"资阳市","经度":104.63,"纬度":30.13,"简介":"号荫柏，邑西黄添湾人。少聪颖，善制科文字，兼工诗古，所到处恒多题咏。聂蓉峰学使深器之，三十岁卒。","主要作品":"著有《荫柏诗稿》"},"geometry":{"type":"Point","coordinates":[104.63,30.13]}},{"type":"Feature","properties":{"序号":191.0,"姓名":"王炳麟","朝代":"清","籍贯(原名)":"安岳县","籍贯(现代)":"资阳安岳县","经度":105.34,"纬度":30.1,"简介":"清代官员，王炳瀛之弟，字芸阁，历任朔州（今朔县）知州。善诗文书法，嘉庆二十三年（1818）中举，道光九年（1829）考取进士。（《安岳县志》）","主要作品":"著有《饮清山房诗文集》《益州书画录》《潼川府志》等著作传世"},"geometry":{"type":"Point","coordinates":[105.34,30.1]}}]}